  });

  scored.sort((a, b) => b.score - a.score);
  const best = scored[0];
  if (!best || best.cover_id == null) {
    return { best: null, confidence: "sin_match", candidates: scored.slice(0, 5) };
  }

  return {
    best,
    confidence: confidenceLevel(best.score),
    candidates: scored.slice(0, 5)
  };
}

// Verifica que la evidencia citada tenga solape lexico real con el texto del
// bullet/cobertura emparejado -- guardrail de grounding (mismo espiritu que
// el guardrail de evidencia del flujo 2, aplicado aqui al texto del Excel en
// vez de al source_text del PDF).
function groundingScore(evidence, candidateText) {
  return jaccard(tokenize(evidence), tokenize(candidateText));
}

// Guardrails y ensamblado del JSON intermedio revisable por humano (nodos
// A13 "Grounding Guardrail", A19 "Tuning Key Guardrail", A21 "Assemble
// Human-Review JSON" y B3 "Validate Review Completeness" del diseño de Fase
// 4 -- ver plan zippy-weaving-crown.md). Codigo puro, se valida offline
// (run_offline_eval.js, check --review-assembly) antes de construir los
// nodos n8n reales.


// A13: verifica que la decision del LLM de matching (Coverage Match Decision
// Agent) no alucine -- (a) el cover_id elegido debe estar entre los
// candidatos ofrecidos, (b) el excel_quote debe ser substring real
// (normalizado) del texto completo de ese candidato (`cover_full_text`,
// mismo campo que ya construye matcher.buildCandidateIndex). Si falla
// cualquiera, degrada la confianza a "baja" -- nunca descarta en silencio,
// mismo patron de visibilidad que el resto de guardrails del proyecto.
function applyGroundingGuardrail(llmDecision, candidates) {
  if (llmDecision.decision !== "match") {
    return { ...llmDecision, grounding_ok: true };
  }

  const candidate = (candidates || []).find(c => c.cover_id === llmDecision.cover_id);
  if (!candidate) {
    return { ...llmDecision, grounding_ok: false, confidence: "baja", degradation_reason: "cover_id_not_in_candidates" };
  }

  const quoteOk = !!llmDecision.excel_quote &&
    normalize(candidate.cover_full_text || "").includes(normalize(llmDecision.excel_quote));
  if (!quoteOk) {
    return { ...llmDecision, grounding_ok: false, confidence: "baja", degradation_reason: "excel_quote_not_grounded" };
  }

  return { ...llmDecision, grounding_ok: true };
}

// A19: valida que el tuning_key devuelto por el Tuning Key Mapping Agent
// exista realmente en el diccionario de tuning de esa compania, o sea
// "NOT_FOUND" explicito (ya senalado como pendiente en
// tuning_key_matcher_prompt.md). Un tuning_key inventado se degrada a
// NOT_FOUND en vez de colarse en el FILTER_EXPR/HIRING_STATUS_EXPR final.
function applyTuningKeyGuardrail(tuningKey, tuningDictionary) {
  if (tuningKey === "NOT_FOUND") {
    return { tuning_key: "NOT_FOUND", valid: true };
  }
  if (tuningDictionary && Object.prototype.hasOwnProperty.call(tuningDictionary, tuningKey)) {
    return { tuning_key: tuningKey, valid: true };
  }
  return { tuning_key: "NOT_FOUND", valid: false, original_tuning_key: tuningKey, reason: "tuning_key_not_in_dictionary" };
}

// Determina si una entrada necesita revision humana (esquema del JSON
// intermedio, ver plan Fase 4): confianza de matching distinta de "alta",
// grounding fallido, o traduccion de valor de enum parcial
// (value_matcher.translateDependencyValue con fullyTranslated: false).
function computeEntryReviewStatus(entry) {
  const reasons = [];
  if (entry.match && entry.match.confidence && entry.match.confidence !== "alta") {
    reasons.push("match_confidence_not_alta");
  }
  if (entry.match && entry.match.grounding_ok === false) {
    reasons.push("grounding_failed");
  }
  if (entry.value_translation && entry.value_translation.fully_translated === false) {
    reasons.push("value_translation_partial");
  }
  return {
    review_status: reasons.length > 0 ? "needs_review" : "auto_approved",
    review_reasons: reasons
  };
}

// A21: ensambla el JSON intermedio final a partir de los registros por
// cobertura ya generados (generator.buildEntriesForCover + metadatos de
// matching/traduccion/tuning adjuntos a cada entry). coverRecords:
// [{coverId, coverName, coverOverride, entries: [{entry_source, bullet_text,
// modality_id, match, dependencies_raw, dependencies_translated,
// value_translation, filter_expr, hiring_status_expr, value_expr,
// tuning_key, human_decision}]}].
function assembleHumanReviewJson({ productCompanyId, ramo, sourceFlow2Artifact, sourceExcel, coverRecords, unmatchedDependencies }) {
  const covers = (coverRecords || []).map(cover => {
    const entries = (cover.entries || []).map(entry => {
      const { review_status, review_reasons } = computeEntryReviewStatus(entry);
      return { ...entry, review_status, review_reasons, human_decision: entry.human_decision ?? null };
    });
    const coverReviewStatus = entries.some(e => e.review_status === "needs_review") ? "needs_review" : "auto_approved";
    return {
      cover_id: cover.coverId,
      cover_name: cover.coverName,
      cover_override_hiring_status_expr: cover.coverOverride ?? null,
      review_status: coverReviewStatus,
      entries
    };
  });

  const totalEntries = covers.reduce((sum, c) => sum + c.entries.length, 0);
  const entriesNeedingReview = covers.reduce(
    (sum, c) => sum + c.entries.filter(e => e.review_status === "needs_review").length,
    0
  );

  return {
    schema_version: "1.0",
    product_company_id: productCompanyId,
    ramo,
    source_flow2_artifact: sourceFlow2Artifact,
    source_excel: sourceExcel,
    summary: {
      total_covers: covers.length,
      covers_needing_review: covers.filter(c => c.review_status === "needs_review").length,
      total_entries: totalEntries,
      entries_needing_review: entriesNeedingReview
    },
    covers,
    unmatched_dependencies: unmatchedDependencies || []
  };
}

// B3: aborta con item de error explicito (nunca rubber-stamp) si queda
// alguna entrada needs_review sin human_decision.action relleno.
function validateReviewCompleteness(reviewJson) {
  const pending = [];
  for (const cover of reviewJson.covers || []) {
    for (const entry of cover.entries || []) {
      if (entry.review_status === "needs_review" && !(entry.human_decision && entry.human_decision.action)) {
        pending.push({ cover_id: cover.cover_id, bullet_text: entry.bullet_text });
      }
    }
  }
  return { complete: pending.length === 0, pending };
}

// --- adaptador n8n (nodo A13) ---
// NOTA (primer borrador, a revisar en n8n con datos reales): asume que
// "Merge Loop Results" combina por posicion el item original (con
// "candidates") y la decision del LLM en el mismo item -- verificar en el
// editor que ambos objetos quedan disponibles juntos (p. ej. bajo
// item.json y item.json.output, segun como serialice el nodo Agent su
// salida) y ajustar el acceso si hace falta.
return $input.all().map(item => {
  const original = item.json;
  const llmDecision = original.output || original;
  const guarded = applyGroundingGuardrail(llmDecision, original.candidates || []);
  return { json: { ...original, ...guarded } };
});

// Matcher offline de VALOR de dependencia (flujo 2, texto libre en español) ->
// valor real de enum en insurance.risk (texto en ingles, p. ej. "MainResidence"
// -- confirmado por el usuario 20/07, ver knowledge/Modelo comparativa de
// coberturas - AI ready.md). Es un paso PREVIO a generator.translateToSpel:
// ese modulo solo traduce {risk_field, operator, value} a sintaxis SPEL, no
// sabe nada de que "vivienda principal" == "MainResidence" -- ese
// conocimiento vive aqui.
//
// Alcance deliberado (YAGNI): solo se cataloga el vocabulario de los enums que
// ya han aparecido con dependencias reales extraidas en produccion
// (housingUse, housingRegime, capitalInsuranceType -- ver golden set de
// evaluators/coverage_dependency_extractor/golden_dataset.json). El resto de
// enums de la ontologia (buildingType, buildQuality, materials, location,
// alarm) no tiene todavia ningun caso real de dependencia -- no se inventa su
// catalogo de valores hasta que aparezca uno.


// Cada entrada: valor real en ingles -> lista de alias en español observados
// en el condicionado. `knownLimitations` documenta frases reales que SI han
// aparecido como valor extraido pero que NO se mapean a ningun valor del enum
// -- no es un hueco por descubrir, es una decision ya tomada (ver memoria
// project_flujo3_implementation_progress, seccion housingUse/alquiler
// vacacional): el usuario opto por dejarlo como limitacion conocida en vez de
// forzar un mapeo o inventar un 4o valor de enum.
const ENUM_VALUE_CATALOG = {
  housingUse: {
    values: {
      MainResidence: ["vivienda principal", "residencia principal", "domicilio habitual", "vivienda habitual"],
      SecondHome: ["vivienda secundaria", "segunda residencia", "vivienda de temporada"],
      UnoccupiedProperty: ["vivienda vacía", "vivienda desocupada", "sin ocupación"]
    },
    knownLimitations: ["alquiler vacacional", "uso turístico", "otros usos", "arrendada"]
  },
  housingRegime: {
    values: {
      Owner: ["propietario"],
      Rental: ["arrendada", "vivienda alquilada"],
      Tenant: ["inquilino", "arrendatario"]
    },
    knownLimitations: [],
    // Caso real 23/07 (su_00127): "propietario" es ambiguo en Hogar entre
    // Owner (ocupa la vivienda) y Rental (la tiene arrendada) -- el
    // condicionado no siempre usa una palabra distinta para cada caso, pero
    // SI aporta la desambiguacion en la misma frase de evidencia cuando
    // aplica ("propietario de una vivienda arrendada..."). Mismo mecanismo
    // que `negative_aliases` de matcher/ontologia pero a nivel de VALOR: el
    // dato (que ramo/campo/palabras) vive aqui, el motor (applyContextOverrides
    // mas abajo) no conoce "housingRegime" ni "arrendada" -- es generico.
    contextOverrides: [
      { from: "Owner", to: "Rental", whenEvidenceContainsAny: ["arrendada", "arrendador", "alquilada", "alquiler"] }
    ]
  },
  capitalInsuranceType: {
    values: {
      FirstRisk: ["primer riesgo", "primer_riesgo"],
      VReplacementValue: ["valor de reposición", "valor de reposicion"]
    },
    knownLimitations: []
  }
};

// Indice alias normalizado -> valor real en ingles, construido una vez por
// risk_field (mismo espiritu que buildIdf/buildCandidateIndex en matcher.js:
// precalcular en vez de recorrer todo en cada llamada).
function buildValueIndex(riskField) {
  const catalog = ENUM_VALUE_CATALOG[riskField];
  if (!catalog) return null;
  const aliasToValue = new Map();
  for (const [value, aliases] of Object.entries(catalog.values)) {
    for (const alias of aliases) aliasToValue.set(normalize(alias), value);
  }
  const knownLimitations = new Set((catalog.knownLimitations || []).map(normalize));
  return { aliasToValue, knownLimitations };
}

// Empareja un valor en español (tal cual lo extrae el flujo 2) contra el
// catalogo del risk_field. No es un match difuso (a diferencia de
// matcher.js/tuning_matcher.js): los valores de enum son un vocabulario
// cerrado y corto, alias exacto (normalizado) es suficiente y mas seguro --
// un match difuso aqui arriesga traducir mal un FILTER_EXPR sin que se note.
function matchEnumValue(riskField, spanishValue) {
  const index = buildValueIndex(riskField);
  if (!index) {
    return { matched: false, value: null, reason: "risk_field_not_cataloged" };
  }
  const normalized = normalize(spanishValue);
  if (index.aliasToValue.has(normalized)) {
    return { matched: true, value: index.aliasToValue.get(normalized), reason: "alias_match" };
  }
  if (index.knownLimitations.has(normalized)) {
    return { matched: false, value: null, reason: "known_limitation" };
  }
  return { matched: false, value: null, reason: "no_alias_match" };
}

// Reinterpreta un valor ya emparejado por matchEnumValue si el catalogo del
// risk_field declara un `contextOverrides` que aplique -- generico por
// diseno: no conoce ningun risk_field ni palabra concreta, solo ejecuta lo
// que el catalogo (dato, no codigo) declare para el risk_field recibido. El
// vocabulario/ramo especifico vive en ENUM_VALUE_CATALOG (mirror ejecutable
// de la ontologia, ver value_context_overrides en ontology-home.md), nunca
// aqui -- asi el motor sirve igual para el catalogo de cualquier ramo futuro.
function applyContextOverrides(riskField, matchedValue, evidence) {
  const rules = ENUM_VALUE_CATALOG[riskField] && ENUM_VALUE_CATALOG[riskField].contextOverrides;
  if (!rules || !matchedValue) return matchedValue;
  const normalizedEvidence = normalize(evidence || "");
  for (const rule of rules) {
    if (rule.from !== matchedValue) continue;
    const hasCue = rule.whenEvidenceContainsAny.some(cue => normalizedEvidence.includes(normalize(cue)));
    if (hasCue) return rule.to;
  }
  return matchedValue;
}

// Traduce el/los valor(es) de una dependencia completa {risk_field, operator,
// value}. Para IN/NOT_IN, value es un array -- se traduce elemento a elemento
// y se reportan por separado los que no se pudieron traducir (visibilidad,
// mismo patron que rejected_dependencies/ungrounded_dependencies del
// guardrail de flujo 2: nunca descartar en silencio).
//
// Bug real detectado 22/07 (produccion, cover 15 "Patronal sobre empleados
// domesticos", dependencia real housingUse NOT_IN ["otros usos"]): esta
// funcion se llama en el nodo real (Translate Dependency Values) para TODAS
// las dependencias del flujo 2, no solo las de campo enum -- y
// matchEnumValue devuelve matched:false/reason:"risk_field_not_cataloged"
// para CUALQUIER risk_field que no sea un enum (ej. "continent > 0"). Sin
// distinguir este caso, ese "no matched" contaba igual que un fallo real de
// traduccion (known_limitation/no_alias_match), marcando fullyTranslated:
// false para la inmensa mayoria de dependencias reales (5 de 6 en una
// ejecucion real muestreada) que ni siquiera son enums -- si el nodo llegara
// a filtrar por ese flag (como deberia, ver mas abajo), se habria descartado
// casi todo. "risk_field_not_cataloged" NO es un fallo -- ese campo
// simplemente no necesita traduccion, se mantiene su valor original.
function translateDependencyValue(dependency) {
  const isArray = Array.isArray(dependency.value);
  const rawValues = isArray ? dependency.value : [dependency.value];
  const results = rawValues.map(v => {
    const matched = matchEnumValue(dependency.risk_field, v);
    if (!matched.matched) return { raw: v, ...matched };
    const overridden = applyContextOverrides(dependency.risk_field, matched.value, dependency.evidence);
    return overridden === matched.value
      ? { raw: v, ...matched }
      : { raw: v, matched: true, value: overridden, reason: "context_override" };
  });

  const realFailures = results.filter(r => !r.matched && r.reason !== "risk_field_not_cataloged");
  const translatedValues = results
    .filter(r => r.matched || r.reason === "risk_field_not_cataloged")
    .map(r => (r.matched ? r.value : r.raw));

  return {
    dependency: {
      ...dependency,
      value: isArray ? translatedValues : (translatedValues[0] ?? dependency.value)
    },
    fullyTranslated: realFailures.length === 0,
    unmatched: realFailures
  };
}

// Adaptador para el nodo real "Translate Dependency Values" (A15): traduce
// TODAS las dependencias de un match, pero solo incluye en
// dependencies_translated las que se tradujeron sin fallos reales -- una
// dependencia con un fallo real (known_limitation/no_alias_match) se
// EXCLUYE por completo, nunca se deja a medias (ej. el bug real de 22/07:
// "!(insurance[\"risk\"].housingUse in {})" -- una lista vacia en el
// FILTER_EXPR final, generada porque antes se incluia igual la dependencia
// con su value ya vaciado por translateDependencyValue). El aggregate
// fully_translated si refleja TODAS las dependencias (incl. las excluidas),
// para que review_assembly.computeEntryReviewStatus pueda seguir marcando
// needs_review cuando corresponda.
function translateDependencies(dependencies) {
  const translations = (dependencies || []).map(dep => translateDependencyValue(dep));
  return {
    dependencies_translated: translations.filter(t => t.fullyTranslated).map(t => t.dependency),
    fully_translated: translations.every(t => t.fullyTranslated),
    unmatched: translations.flatMap(t => t.unmatched)
  };
}

// Matcher offline dependencia (flujo 2) -> COVER_ID/bullet del Excel de coberturas.
//
// Este modulo implementa SOLO la parte determinista/heuristica del matcher
// (candidatos por similitud lexica + verificacion de grounding). La decision
// final en produccion la toma un LLM con estos candidatos como contexto (ver
// plan de flujo 3) -- aqui no se llama a ningun LLM, es la capa que se valida
// offline antes de construir el nodo n8n real (CLAUDE.md SS7).
//
// Cuando se construya el workflow n8n de flujo 3 (Fase 4 del plan), el codigo
// de esta funcion debe copiarse (o extraerse, siguiendo el mismo patron que
// evaluators/coverage_dependency_extractor/run_offline_eval.js) al Code node
// real que genera los candidatos antes de la llamada LLM.

const STOPWORDS = new Set([
  "de","la","el","los","las","en","y","o","del","con","por","para","que",
  "un","una","al","su","sus","a","e","u","es","se","lo","como","no","si",
  "the","of"
]);

function normalize(str) {
  return (str || "")
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[̀-ͯ]/g, "") // quitar acentos
    .replace(/^[\d]+(\.[\d]+)*\.?\s*/,"") // quitar numeracion inicial "3.2. "
    .replace(/^[a-z]\)\s*/,"") // quitar numeracion tipo "a) "
    .replace(/^articulo\s+[\wº.]+\s*/,"") // quitar "Articulo 8º "
    .replace(/[^a-z0-9\s]/g," ")
    .replace(/\s+/g," ")
    .trim();
}

function tokenize(str) {
  return normalize(str)
    .split(" ")
    .filter(tok => tok.length > 0 && !STOPWORDS.has(tok));
}

function jaccard(tokensA, tokensB) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  let intersection = 0;
  for (const tok of setA) if (setB.has(tok)) intersection++;
  const union = new Set([...setA, ...setB]).size;
  return intersection / union;
}

// Jaccard ponderado por rareza (idf-like): una palabra que aparece en pocos
// candidatos del indice (p. ej. "plagas") pesa mucho mas que una que aparece
// en casi todos (p. ej. "asistencia", "daños", "robo" -- genericas del dominio
// asegurador). Sin esto, una etiqueta estructural corta y generica (p. ej.
// "Asistencia") puede ganarle a un match especifico y correcto por pura
// coincidencia de una sola palabra comun (caso real detectado: GD-MATCH-025).
function weightedJaccard(tokensA, tokensB, idf) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  const all = new Set([...setA, ...setB]);
  let intersection = 0;
  let union = 0;
  for (const tok of all) {
    const w = idf.get(tok) || 1;
    union += w;
    if (setA.has(tok) && setB.has(tok)) intersection += w;
  }
  return union === 0 ? 0 : intersection / union;
}

// Frecuencia de documento inversa sobre los textos del indice de candidatos:
// cuantos menos candidatos contienen una palabra, mas discriminante es.
function buildIdf(candidateIndex) {
  const docFreq = new Map();
  const totalDocs = candidateIndex.length || 1;
  for (const candidate of candidateIndex) {
    const uniqueTokens = new Set(tokenize(candidate.text));
    for (const tok of uniqueTokens) docFreq.set(tok, (docFreq.get(tok) || 0) + 1);
  }
  const idf = new Map();
  for (const [tok, df] of docFreq) idf.set(tok, Math.log((totalDocs + 1) / (df + 1)) + 1);
  return idf;
}

// Construye el indice plano de candidatos (cover_id + texto) a partir del
// fixture normalizado del Excel (ambas hojas). Cada candidato lleva ademas
// `cover_full_text` (nombre + todos los bullets de esa cobertura) para el
// guardrail de grounding -- la evidencia de una dependencia describe la
// condicion, no necesariamente repite las palabras del bullet exacto, asi que
// el grounding se comprueba contra el contenido completo de la cobertura, no
// solo el fragmento que gano el matching.
function buildCandidateIndex(excelFixture) {
  const index = [];
  const byCoverName = new Map();
  const fullTextByCoverId = new Map();

  for (const cover of excelFixture.covers_por_modalidad || []) {
    byCoverName.set(normalize(cover.cover_name), cover.cover_id);
    fullTextByCoverId.set(
      cover.cover_id,
      [cover.cover_name, ...(cover.sample_text_bullets || [])].join(" ")
    );
  }
  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    if (parentCoverId != null) {
      fullTextByCoverId.set(
        parentCoverId,
        (fullTextByCoverId.get(parentCoverId) || "") + " " + opt.cover_name + " " + (opt.text_content || "")
      );
    }
  }

  for (const cover of excelFixture.covers_por_modalidad || []) {
    index.push({
      cover_id: cover.cover_id,
      text: cover.cover_name,
      cover_full_text: fullTextByCoverId.get(cover.cover_id) || cover.cover_name,
      source: "modality_cover_name"
    });
    for (const bullet of cover.sample_text_bullets || []) {
      index.push({
        cover_id: cover.cover_id,
        text: bullet,
        cover_full_text: fullTextByCoverId.get(cover.cover_id) || bullet,
        source: "modality_bullet"
      });
    }
  }

  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    index.push({
      cover_id: parentCoverId,
      text: opt.cover_name,
      cover_full_text: fullTextByCoverId.get(parentCoverId) || opt.cover_name,
      source: "optional_cover_name",
      exact_optional_name: normalize(opt.cover_name)
    });
  }

  return index;
}

const CONFIDENCE_THRESHOLDS = { alta: 0.55, media: 0.3 };

function confidenceLevel(score) {
  if (score >= CONFIDENCE_THRESHOLDS.alta) return "alta";
  if (score >= CONFIDENCE_THRESHOLDS.media) return "media";
  return "sin_match";
}

// coveragePath: array de strings (jerarquia interna del condicionado, la
// produce el flujo 2). article: titulo del articulo (fallback quando
// coverage_path viene vacio). evidenceText: texto real de la dependencia/
// evidencia (source_text o evidence concatenada) -- necesario porque la
// etiqueta estructural (coverage_path/article) puede ser enganosa (caso real:
// "Articulo 9 Asistencia" que en realidad habla de control de plagas, ver
// golden set GD-MATCH-025) y el contenido real desempata correctamente.
function matchDependency(coveragePath, article, evidenceText, candidateIndex) {
  const leafText = (coveragePath || [])[coveragePath.length - 1] || "";
  const leafNormalized = normalize(leafText);
  const leafTokens = tokenize(leafText);
  const rootText = (coveragePath || [])[0] || "";
  const rootNormalized = normalize(rootText);
  const rootTokens = tokenize(rootText + " " + (article || ""));
  const evidenceTokens = tokenize(evidenceText || "");
  const idf = buildIdf(candidateIndex);

  const scored = candidateIndex.map(candidate => {
    // Match exacto por nombre (hoja "Coberturas opcionales" -> join directo,
    // sin necesidad de similitud difusa). El nombre de la opcional puede
    // corresponder tanto al nivel hoja como al nivel raiz de coverage_path
    // (el desglose interno del condicionado no siempre alinea sus niveles con
    // el nombre exacto de la opcional en el mismo nivel).
    if (candidate.exact_optional_name &&
        (candidate.exact_optional_name === leafNormalized || candidate.exact_optional_name === rootNormalized)) {
      return { ...candidate, score: 1.0, match_type: "exact_optional_name" };
    }
    const candidateTokens = tokenize(candidate.text);
    const leafScore = weightedJaccard(leafTokens, candidateTokens, idf);
    const rootScore = weightedJaccard(rootTokens, candidateTokens, idf);
    const evidenceScore = weightedJaccard(evidenceTokens, candidateTokens, idf);
    // El nivel hoja (bullet concreto) es la senal mas especifica; el texto
    // real de la evidencia puede desempatar o corregir cuando la etiqueta
    // estructural es enganosa (palabras raras como "plagas" pesan mucho mas
    // que genericas como "asistencia" gracias al idf); el nivel raiz solo
    // ayuda para candidatos de nombre de cobertura completo.
    const score = Math.max(leafScore, evidenceScore * 0.9, rootScore * 0.8);
    return { ...candidate, score, match_type: "lexical" };
  });

  scored.sort((a, b) => b.score - a.score);
  const best = scored[0];
  if (!best || best.cover_id == null) {
    return { best: null, confidence: "sin_match", candidates: scored.slice(0, 5) };
  }

  return {
    best,
    confidence: confidenceLevel(best.score),
    candidates: scored.slice(0, 5)
  };
}

// Verifica que la evidencia citada tenga solape lexico real con el texto del
// bullet/cobertura emparejado -- guardrail de grounding (mismo espiritu que
// el guardrail de evidencia del flujo 2, aplicado aqui al texto del Excel en
// vez de al source_text del PDF).
function groundingScore(evidence, candidateText) {
  return jaccard(tokenize(evidence), tokenize(candidateText));
}

// --- adaptador n8n (nodo A15) ---
// Traduce cada dependencia de cada semantic unit ya emparejado (decision ===
// "match") ANTES de que el generador de SPEL vea el valor -- generator.js
// sigue sin saber nada de traduccion de idioma (deliberado, ver su cabecera).
// Bug real corregido 22/07 (cover 15 "Patronal sobre empleados domesticos"):
// antes se incluia en dependencies_translated CUALQUIER dependencia,
// incluida una con fallo real de traduccion (su value quedaba vacio, ej.
// housingUse NOT_IN [] -- vacio porque "otros usos" no traduce), generando
// un FILTER_EXPR final sin sentido ("!(campo in {})"). value_matcher.
// translateDependencies excluye por completo esas dependencias (nunca las
// deja a medias), conservando las de campo no-enum (nunca fueron un fallo).
return $input.all().map(item => {
  const data = item.json;
  if (data.decision !== "match") return { json: data };
  const { dependencies_translated, fully_translated, unmatched } = translateDependencies(data.dependencies);
  return {
    json: {
      ...data,
      dependencies_translated,
      value_translation: { fully_translated, unmatched }
    }
  };
});

// Matcher offline dependencia (flujo 2) -> COVER_ID/bullet del Excel de coberturas.
//
// Este modulo implementa SOLO la parte determinista/heuristica del matcher
// (candidatos por similitud lexica + verificacion de grounding). La decision
// final en produccion la toma un LLM con estos candidatos como contexto (ver
// plan de flujo 3) -- aqui no se llama a ningun LLM, es la capa que se valida
// offline antes de construir el nodo n8n real (CLAUDE.md SS7).
//
// Cuando se construya el workflow n8n de flujo 3 (Fase 4 del plan), el codigo
// de esta funcion debe copiarse (o extraerse, siguiendo el mismo patron que
// evaluators/coverage_dependency_extractor/run_offline_eval.js) al Code node
// real que genera los candidatos antes de la llamada LLM.

const STOPWORDS = new Set([
  "de","la","el","los","las","en","y","o","del","con","por","para","que",
  "un","una","al","su","sus","a","e","u","es","se","lo","como","no","si",
  "the","of"
]);

function normalize(str) {
  return (str || "")
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[̀-ͯ]/g, "") // quitar acentos
    .replace(/^[\d]+(\.[\d]+)*\.?\s*/,"") // quitar numeracion inicial "3.2. "
    .replace(/^[a-z]\)\s*/,"") // quitar numeracion tipo "a) "
    .replace(/^articulo\s+[\wº.]+\s*/,"") // quitar "Articulo 8º "
    .replace(/[^a-z0-9\s]/g," ")
    .replace(/\s+/g," ")
    .trim();
}

function tokenize(str) {
  return normalize(str)
    .split(" ")
    .filter(tok => tok.length > 0 && !STOPWORDS.has(tok));
}

function jaccard(tokensA, tokensB) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  let intersection = 0;
  for (const tok of setA) if (setB.has(tok)) intersection++;
  const union = new Set([...setA, ...setB]).size;
  return intersection / union;
}

// Jaccard ponderado por rareza (idf-like): una palabra que aparece en pocos
// candidatos del indice (p. ej. "plagas") pesa mucho mas que una que aparece
// en casi todos (p. ej. "asistencia", "daños", "robo" -- genericas del dominio
// asegurador). Sin esto, una etiqueta estructural corta y generica (p. ej.
// "Asistencia") puede ganarle a un match especifico y correcto por pura
// coincidencia de una sola palabra comun (caso real detectado: GD-MATCH-025).
function weightedJaccard(tokensA, tokensB, idf) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  const all = new Set([...setA, ...setB]);
  let intersection = 0;
  let union = 0;
  for (const tok of all) {
    const w = idf.get(tok) || 1;
    union += w;
    if (setA.has(tok) && setB.has(tok)) intersection += w;
  }
  return union === 0 ? 0 : intersection / union;
}

// Frecuencia de documento inversa sobre los textos del indice de candidatos:
// cuantos menos candidatos contienen una palabra, mas discriminante es.
function buildIdf(candidateIndex) {
  const docFreq = new Map();
  const totalDocs = candidateIndex.length || 1;
  for (const candidate of candidateIndex) {
    const uniqueTokens = new Set(tokenize(candidate.text));
    for (const tok of uniqueTokens) docFreq.set(tok, (docFreq.get(tok) || 0) + 1);
  }
  const idf = new Map();
  for (const [tok, df] of docFreq) idf.set(tok, Math.log((totalDocs + 1) / (df + 1)) + 1);
  return idf;
}

// Construye el indice plano de candidatos (cover_id + texto) a partir del
// fixture normalizado del Excel (ambas hojas). Cada candidato lleva ademas
// `cover_full_text` (nombre + todos los bullets de esa cobertura) para el
// guardrail de grounding -- la evidencia de una dependencia describe la
// condicion, no necesariamente repite las palabras del bullet exacto, asi que
// el grounding se comprueba contra el contenido completo de la cobertura, no
// solo el fragmento que gano el matching.
function buildCandidateIndex(excelFixture) {
  const index = [];
  const byCoverName = new Map();
  const fullTextByCoverId = new Map();

  for (const cover of excelFixture.covers_por_modalidad || []) {
    byCoverName.set(normalize(cover.cover_name), cover.cover_id);
    fullTextByCoverId.set(
      cover.cover_id,
      [cover.cover_name, ...(cover.sample_text_bullets || [])].join(" ")
    );
  }
  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    if (parentCoverId != null) {
      fullTextByCoverId.set(
        parentCoverId,
        (fullTextByCoverId.get(parentCoverId) || "") + " " + opt.cover_name + " " + (opt.text_content || "")
      );
    }
  }

  for (const cover of excelFixture.covers_por_modalidad || []) {
    index.push({
      cover_id: cover.cover_id,
      text: cover.cover_name,
      cover_full_text: fullTextByCoverId.get(cover.cover_id) || cover.cover_name,
      source: "modality_cover_name"
    });
    for (const bullet of cover.sample_text_bullets || []) {
      index.push({
        cover_id: cover.cover_id,
        text: bullet,
        cover_full_text: fullTextByCoverId.get(cover.cover_id) || bullet,
        source: "modality_bullet"
      });
    }
  }

  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    index.push({
      cover_id: parentCoverId,
      text: opt.cover_name,
      cover_full_text: fullTextByCoverId.get(parentCoverId) || opt.cover_name,
      source: "optional_cover_name",
      exact_optional_name: normalize(opt.cover_name)
    });
  }

  return index;
}

const CONFIDENCE_THRESHOLDS = { alta: 0.55, media: 0.3 };

function confidenceLevel(score) {
  if (score >= CONFIDENCE_THRESHOLDS.alta) return "alta";
  if (score >= CONFIDENCE_THRESHOLDS.media) return "media";
  return "sin_match";
}

// coveragePath: array de strings (jerarquia interna del condicionado, la
// produce el flujo 2). article: titulo del articulo (fallback quando
// coverage_path viene vacio). evidenceText: texto real de la dependencia/
// evidencia (source_text o evidence concatenada) -- necesario porque la
// etiqueta estructural (coverage_path/article) puede ser enganosa (caso real:
// "Articulo 9 Asistencia" que en realidad habla de control de plagas, ver
// golden set GD-MATCH-025) y el contenido real desempata correctamente.
function matchDependency(coveragePath, article, evidenceText, candidateIndex) {
  const leafText = (coveragePath || [])[coveragePath.length - 1] || "";
  const leafNormalized = normalize(leafText);
  const leafTokens = tokenize(leafText);
  const rootText = (coveragePath || [])[0] || "";
  const rootNormalized = normalize(rootText);
  const rootTokens = tokenize(rootText + " " + (article || ""));
  const evidenceTokens = tokenize(evidenceText || "");
  const idf = buildIdf(candidateIndex);

  const scored = candidateIndex.map(candidate => {
    // Match exacto por nombre (hoja "Coberturas opcionales" -> join directo,
    // sin necesidad de similitud difusa). El nombre de la opcional puede
    // corresponder tanto al nivel hoja como al nivel raiz de coverage_path
    // (el desglose interno del condicionado no siempre alinea sus niveles con
    // el nombre exacto de la opcional en el mismo nivel).
    if (candidate.exact_optional_name &&
        (candidate.exact_optional_name === leafNormalized || candidate.exact_optional_name === rootNormalized)) {
      return { ...candidate, score: 1.0, match_type: "exact_optional_name" };
    }
    const candidateTokens = tokenize(candidate.text);
    const leafScore = weightedJaccard(leafTokens, candidateTokens, idf);
    const rootScore = weightedJaccard(rootTokens, candidateTokens, idf);
    const evidenceScore = weightedJaccard(evidenceTokens, candidateTokens, idf);
    // El nivel hoja (bullet concreto) es la senal mas especifica; el texto
    // real de la evidencia puede desempatar o corregir cuando la etiqueta
    // estructural es enganosa (palabras raras como "plagas" pesan mucho mas
    // que genericas como "asistencia" gracias al idf); el nivel raiz solo
    // ayuda para candidatos de nombre de cobertura completo.
    const score = Math.max(leafScore, evidenceScore * 0.9, rootScore * 0.8);
    return { ...candidate, score, match_type: "lexical" };
  });

  scored.sort((a, b) => b.score - a.score);
  const best = scored[0];
  if (!best || best.cover_id == null) {
    return { best: null, confidence: "sin_match", candidates: scored.slice(0, 5) };
  }

  return {
    best,
    confidence: confidenceLevel(best.score),
    candidates: scored.slice(0, 5)
  };
}

// Verifica que la evidencia citada tenga solape lexico real con el texto del
// bullet/cobertura emparejado -- guardrail de grounding (mismo espiritu que
// el guardrail de evidencia del flujo 2, aplicado aqui al texto del Excel en
// vez de al source_text del PDF).
function groundingScore(evidence, candidateText) {
  return jaccard(tokenize(evidence), tokenize(candidateText));
}

// Parser de bloques/lines a partir del texto enriquecido (negrita) de una
// celda real de "Coberturas por modalidad" (Google Sheets API,
// spreadsheets.get?includeGridData=true -> rowData[].values[].
// {formattedValue, textFormatRuns, effectiveFormat}).
//
// Motivo (revision manual del usuario, 22/07, cover_id 15/16/17/22 de
// Generali): el texto libre de una celda no es una lista plana de bullets --
// tiene una jerarquia real de bloque/linea que el troceo actual por "\n"
// (splitBulletsFromCellText en generator.js) no captura. La negrita marca
// SIEMPRE un segmento destacado dentro de la celda, pero su rol semantico
// varia por cobertura (confirmado con datos reales de las 4 coberturas
// citadas, ver evaluators/coverage_insert_generator/rich_text_block_parser_golden_dataset.json):
//   - cover 15 (RC): negrita = un VALOR suelto (Capital ...€), su propio
//     bloque; el cuerpo (sin negrita) mezcla lineas con "-" (nueva
//     sub-cobertura, ej. "-Responsabilidad Civil de la vivienda") y lineas
//     sin "-" (detalle de la sub-cobertura anterior, ej. "Como propietario").
//   - cover 16 (Robo) / 17 (Incendio): negrita = una ETIQUETA (titulo o
//     descripcion), el cuerpo es una lista plana SIN ningun "-" -- va todo
//     como lineas de un unico bloque encabezado por la negrita.
//   - cover 22 (Asistencia): negrita = etiqueta de bloque ("... incluida:"),
//     el cuerpo es una lista plana pero CON "-" en todas sus lineas (el "-"
//     aqui es solo marca de vineta, no separador de sub-bloque, porque
//     ninguna linea tiene a su vez lineas hijas mas indentadas debajo).
//
// Regla de deteccion (ver clasificarCuerpo): un cuerpo se considera MIXTO
// (mezcla lineas con y sin "-") solo cuando eso ocurre -- ahi cada linea con
// "-" abre un bloque nuevo (independiente de la negrita que la precede) y
// las lineas sin "-" que le siguen son su detalle. Un cuerpo UNIFORME (todo
// con "-" o nada con "-") se trata como una lista plana de lineas del bloque
// que encabeza la negrita -- el "-" ahi es solo viñeta, no jerarquia.
//
// Casos que esta regla no puede resolver de forma fiable (marcados
// needsReview en vez de adivinar):
//   - una negrita con mas de 1 linea (nunca visto en los datos reales).
//   - una etiqueta (negrita no-valor) seguida de un cuerpo MIXTO (nunca
//     visto -- en cover 15 el mixto aparece siempre bajo un VALOR, no una
//     etiqueta).
//   - una linea sin "-" que aparece antes de la primera linea con "-" dentro
//     de un cuerpo mixto (no tiene bloque al que asignarse).
//
// Deliberadamente NO resuelve aqui la ambiguedad "estas lineas planas, son
// la MISMA cobertura o varian por modalidad" (cover 16 vs. 17) -- eso ya lo
// resuelve, a nivel de BLOQUE (no de linea suelta), la logica de familias
// por contenido exacto entre modalidades de excel_fixture_builder.js
// (buildBlockGroupsForCover/buildBlockGroupsForHeterogeneousCover). Este
// modulo solo entrega el bloque candidato; la variacion entre modalidades se
// aplica despues.

const VALUE_HEADER_PATTERN = /^(capital|suma asegurada|l[íi]mite|importe)\b.*\d/i;

function buildIsBoldAt(textFormatRuns, fallbackBold) {
  if (!Array.isArray(textFormatRuns) || textFormatRuns.length === 0) {
    return () => !!fallbackBold;
  }
  const runs = textFormatRuns
    .map(r => ({ start: r.startIndex ?? 0, bold: !!(r.format && r.format.bold) }))
    .sort((a, b) => a.start - b.start);
  return function isBoldAt(idx) {
    let bold = false;
    for (const run of runs) {
      if (run.start <= idx) bold = run.bold;
      else break;
    }
    return bold;
  };
}

// Divide el texto completo en segmentos de negrita/no-negrita POR CARACTER
// (no por linea) -- la negrita puede terminar A MITAD de una linea fisica
// (bug real 22/07, covers 21 "Restauración Estética" y 104 "Otras
// garantías": "Restauración Estética Continente" en negrita seguido de " -
// 3.000€" sin negrita, ambos en la MISMA linea). Clasificar por linea
// completa (mirando solo su primer caracter, como hacia la version
// anterior) fusionaba estos casos con la linea siguiente en un unico bloque
// con los textos concatenados. Cada segmento lleva ademas
// `startsNewPhysicalLine`: si arranca justo despues de un "\n" real (o al
// principio de la celda) frente a si continua, sin salto de linea, el
// segmento de negrita distinta anterior -- usado en analyzeLines para
// distinguir "linea fisica nueva" de "resto de la misma linea con formato
// distinto" (ver `continuesPreviousLine`).
function buildCharSegments(text, isBoldAt) {
  const segments = [];
  if (!text) return segments;
  let start = 0;
  let currentBold = isBoldAt(0);
  for (let i = 1; i <= text.length; i++) {
    const bold = i < text.length ? isBoldAt(i) : !currentBold; // fuerza el flush final
    if (bold !== currentBold || i === text.length) {
      segments.push({
        text: text.slice(start, i),
        bold: currentBold,
        startsNewPhysicalLine: start === 0 || text[start - 1] === "\n"
      });
      start = i;
      currentBold = bold;
    }
  }
  return segments;
}

// Clasifica cada linea no vacia de la celda: texto recortado, si arranca por
// "-" y si es negrita. Cada segmento de negrita/no-negrita (ver
// buildCharSegments) se trocea a su vez por "\n" -- un segmento puede
// contener varias lineas completas (cabecera en negrita multilinea, ver
// needsReview en classifyBoldRun) o ser solo un FRAGMENTO de una linea (el
// resto de esa misma linea fisica sigue en el siguiente segmento, con
// negrita distinta); en ambos casos el resultado son fragmentos de texto en
// el orden real de la celda, cada uno con su propia negrita ya resuelta con
// precision de caracter -- no hace falta ninguna heuristica adicional para
// el caso de espacios sobrantes antes de un "\n" (el propio split ya deja
// ese fragmento vacio, descartado por el filtro de lineas en blanco).
//
// `continuesPreviousLine`: true solo para el PRIMER fragmento de un segmento
// que no arranca justo despues de un "\n" real -- es decir, cuando un cambio
// de negrita ocurre A MITAD de una linea fisica (ej. cover 21 "Restauración
// Estética Continente" negrita + " - 3.000€" sin negrita, misma linea). Se
// usa en parseModalityCellBlocks para reunir de nuevo ese fragmento con la
// linea anterior (la cabecera) en vez de tratarlo como una linea de cuerpo
// independiente -- sin alterar la deteccion de bloques/runs, que sigue
// operando sobre lineas separadas como antes.
function analyzeLines(formattedValue, textFormatRuns, effectiveFormatBold) {
  const isBoldAt = buildIsBoldAt(textFormatRuns, effectiveFormatBold);
  const segments = buildCharSegments(formattedValue || "", isBoldAt);

  const result = [];
  for (const segment of segments) {
    segment.text.split("\n").forEach((raw, pieceIdx) => {
      const trimmed = raw.trim();
      if (trimmed.length === 0) return;
      const continuesPreviousLine = pieceIdx === 0 && !segment.startsNewPhysicalLine;
      result.push({ text: trimmed, isDash: /^-/.test(trimmed), bold: segment.bold, continuesPreviousLine });
    });
  }
  return result;
}

// Agrupa lineas consecutivas con la misma negrita en "runs" (secuencia
// bold/no-bold, en el orden real de la celda).
function groupIntoRuns(lines) {
  const runs = [];
  for (const line of lines) {
    const last = runs[runs.length - 1];
    if (last && last.bold === line.bold) {
      last.lines.push(line);
    } else {
      runs.push({ bold: line.bold, lines: [line] });
    }
  }
  return runs;
}

function classifyBoldRun(run) {
  const text = run.lines.map(l => l.text).join(" ");
  return {
    text,
    kind: VALUE_HEADER_PATTERN.test(text) ? "value" : "label",
    needsReview: run.lines.length > 1,
    reviewReason: run.lines.length > 1 ? "bold_header_multiline" : null
  };
}

// Decide si un cuerpo (run sin negrita) es MIXTO (arranca sub-bloques por
// "-") o UNIFORME (lista plana, el "-" si aparece es solo vineta).
function splitBodyRun(run) {
  const hasDash = run.lines.some(l => l.isDash);
  const hasNonDash = run.lines.some(l => !l.isDash);
  const mixed = hasDash && hasNonDash;

  if (!mixed) {
    return { mode: "flat", lines: run.lines.map(l => l.text) };
  }

  const blocks = [];
  for (const line of run.lines) {
    if (line.isDash) {
      blocks.push({ headerText: line.text, lines: [] });
    } else if (blocks.length > 0) {
      blocks[blocks.length - 1].lines.push(line.text);
    } else {
      blocks.push({ headerText: null, lines: [line.text], needsReview: true, reviewReason: "line_before_first_dash_in_mixed_body" });
    }
  }
  return { mode: "dash-split", blocks };
}

// Si la primera linea de un bodyRun es en realidad el resto (sin negrita)
// de la MISMA linea fisica que la cabecera en negrita (continuesPreviousLine,
// ver analyzeLines), la reune con la cabecera en vez de dejarla como una
// linea de cuerpo aparte -- caso real cover 21/104: "Restauración Estética
// Continente" (negrita) + " - 3.000€" (sin negrita), misma linea -> una
// unica linea "Restauración Estética Continente - 3.000€". Solo afecta a la
// PRIMERA linea del bodyRun (el resto, si lo hay, son lineas fisicas reales
// -- separadas por un "\n" real -- y siguen su deteccion de guion/mixto
// habitual sin tocar).
function mergeLineContinuationIntoHeader(headerText, bodyLines) {
  if (bodyLines.length > 0 && bodyLines[0].continuesPreviousLine) {
    return { headerText: `${headerText} ${bodyLines[0].text}`, lines: bodyLines.slice(1) };
  }
  return { headerText, lines: bodyLines };
}

function expandBodyAsSiblingBlocks(run) {
  const split = splitBodyRun(run);
  if (split.mode === "flat") {
    return [{ kind: "flat", headerText: null, lines: split.lines, needsReview: false, reviewReason: null }];
  }
  return split.blocks.map(b => ({
    kind: "dash",
    headerText: b.headerText,
    lines: b.lines,
    needsReview: !!b.needsReview,
    reviewReason: b.reviewReason || null
  }));
}

// Entrada principal. cell: {formattedValue, textFormatRuns, effectiveFormat}
// tal cual lo devuelve la API real de Google Sheets (ver cabecera).
// Salida: { blocks: [{kind, headerText, lines, needsReview, reviewReason}] }
// -- kind: "value" (bloque = un valor suelto, ej. capital), "label" (bloque
// encabezado por una etiqueta en negrita con su cuerpo como lineas), "dash"
// (sub-bloque abierto por una linea "-" dentro de un cuerpo mixto), "flat"
// (lista plana sin negrita ni jerarquia -- lineas sueltas de una unica
// entrada, sin cabecera propia).
function parseModalityCellBlocks(cell) {
  const effectiveBold = cell.effectiveFormat && cell.effectiveFormat.textFormat && cell.effectiveFormat.textFormat.bold;
  const lines = analyzeLines(cell.formattedValue, cell.textFormatRuns, effectiveBold);
  const runs = groupIntoRuns(lines);

  const blocks = [];
  let i = 0;
  while (i < runs.length) {
    const run = runs[i];

    if (!run.bold) {
      blocks.push(...expandBodyAsSiblingBlocks(run));
      i += 1;
      continue;
    }

    const boldInfo = classifyBoldRun(run);
    const bodyRun = runs[i + 1] && !runs[i + 1].bold ? runs[i + 1] : null;

    if (boldInfo.kind === "value") {
      blocks.push({ kind: "value", headerText: boldInfo.text, lines: [], needsReview: boldInfo.needsReview, reviewReason: boldInfo.reviewReason });
      if (bodyRun) {
        blocks.push(...expandBodyAsSiblingBlocks(bodyRun));
        i += 2;
      } else {
        i += 1;
      }
      continue;
    }

    if (!bodyRun) {
      blocks.push({ kind: "label", headerText: boldInfo.text, lines: [], needsReview: boldInfo.needsReview, reviewReason: boldInfo.reviewReason });
      i += 1;
      continue;
    }

    const merged = mergeLineContinuationIntoHeader(boldInfo.text, bodyRun.lines);
    const split = splitBodyRun({ lines: merged.lines });
    if (split.mode === "flat") {
      blocks.push({ kind: "label", headerText: merged.headerText, lines: split.lines, needsReview: boldInfo.needsReview, reviewReason: boldInfo.reviewReason });
    } else {
      blocks.push({ kind: "label", headerText: merged.headerText, lines: [], needsReview: true, reviewReason: "mixed_body_under_label" });
      blocks.push(...split.blocks.map(b => ({
        kind: "dash",
        headerText: b.headerText,
        lines: b.lines,
        needsReview: !!b.needsReview,
        reviewReason: b.reviewReason || null
      })));
    }
    i += 2;
  }

  return { blocks };
}

// Lista ordenada de "segmentos" de texto de un bloque -- cabecera (si el
// kind la tiene) seguida de sus lineas, o solo las lineas para un bloque
// "flat" sin cabecera propia. Es el mismo orden que usan
// generator.buildBlockLines (para construir las LINES reales) y
// excel_fixture_builder.matchDependenciesForBlock (para emparejar
// dependencias) -- se expone aqui para que ambos consumidores, y cualquier
// codigo que necesite comparar la "forma" (numero de segmentos) de dos
// bloques, usen siempre el mismo criterio sin duplicarlo.
function segmentTextsOf(block) {
  if (block.kind === "value") return [block.headerText];
  if (block.kind === "flat") return block.lines || [];
  return [block.headerText, ...(block.lines || [])].filter(Boolean);
}

// Adaptadores entre la salida de los nodos de limpieza del Excel (`Clean
// covers and modalities` / `Clean Optional Covers`) y lo que esperan
// `matcher.js` (indice de candidatos) y `generator.js` (bloques por
// cobertura, agrupados por si varian o no entre modalidades). Corresponde a
// los nodos A6 ("Build Excel Fixture for Matcher") y A16 ("Build Per-Cover
// Block Groups") del diseño de Fase 4 (ver plan zippy-weaving-crown.md).
// Los bloques vienen de rich_text_block_parser.js (negrita/"-" de la celda
// real de Google Sheets, diseno 22/07) -- ver ese fichero para el criterio
// de bloque/linea. Codigo puro, se valida offline (run_offline_eval.js,
// check --excel-fixture) antes de construir los nodos n8n reales.



// Marcador de texto libre (sin relacion con ninguna cobertura real) que el
// Excel usa dentro de una celda de "Coberturas por modalidad" para senalar
// que esa modalidad necesita mapeo a un tuning_key (ver Build Tuning
// Context). No es contenido real de la cobertura -- debe excluirse de los
// bullets antes de construir candidatos/ENTRY, o se cuela como una linea
// literal "Garantía Opcional" visible al usuario final (caso real
// confirmado: COVER_ID 79/81).
const GARANTIA_OPCIONAL_MARKER_NORMALIZED = normalize("Garantía Opcional");

function isGarantiaOpcionalMarker(bulletText) {
  return normalize(bulletText) === GARANTIA_OPCIONAL_MARKER_NORMALIZED;
}

// A6: cleanedModalityCovers = salida de `Clean covers and modalities`
// ({cover_id, cover_name, modalities: {modality_id: cell}}[], cell = celda
// rica de Google Sheets -- {formattedValue, textFormatRuns, effectiveFormat},
// ver rich_text_block_parser.js). cleanedOptionalCovers = salida de `Clean
// Optional Covers` extendida con `epigrafe` (texto crudo de la columna
// EPIGRAFE, ver nota A5 del diseño). Produce el fixture exacto que espera
// matcher.buildCandidateIndex -- los candidatos de texto salen de aplanar
// TODOS los segmentos (cabecera+lineas) de TODOS los bloques de la celda,
// via blocksFromCell/segmentTextsOf (mismo parser que usa el resto del
// modulo, sin una segunda logica de troceo divergente).
function buildExcelFixtureForMatcher(cleanedModalityCovers, cleanedOptionalCovers) {
  const covers_por_modalidad = (cleanedModalityCovers || []).map(cover => {
    const seen = new Set();
    const sample_text_bullets = [];
    for (const cell of Object.values(cover.modalities || {})) {
      const blocks = blocksFromCell(cell, cover.cover_name);
      for (const block of blocks) {
        for (const text of segmentTextsOf(block)) {
          const key = normalize(text);
          if (!seen.has(key)) {
            seen.add(key);
            sample_text_bullets.push(text);
          }
        }
      }
    }
    return { cover_id: cover.cover_id, cover_name: cover.cover_name, sample_text_bullets };
  });

  const coberturas_opcionales = (cleanedOptionalCovers || []).map(opt => ({
    epigrafe: opt.epigrafe,
    cover_name: opt.cover_name,
    text_content: opt.text_content
  }));

  return { covers_por_modalidad, coberturas_opcionales };
}

// Serializa un bloque (ver rich_text_block_parser.parseModalityCellBlocks)
// a una clave comparable, normalizada igual que el resto del modulo -- dos
// bloques son "el mismo" (misma familia) solo si coinciden kind+cabecera+
// TODAS sus lineas, no solo el texto de la cabecera (la cabecera de un
// bloque "value" -- ej. "Capital 150.000€" -- ya varia por modalidad por
// diseno, asi que ahi la clave siempre sera distinta entre modalidades:
// correcto, cada capital es su propia variante).
function serializeBlockForComparison(block) {
  return normalize([block.kind, block.headerText || "", ...(block.lines || [])].join("|"));
}

// Patron real observado (celdas de "Coberturas por modalidad"): la celda
// repite el propio nombre de la cobertura a modo de cabecera antes del
// contenido real. Puede aparecer de 2 formas -- confirmado con datos reales
// 22/07, COVER_ID 18 "Daños por agua": el nombre esta en NEGRITA (bloque
// "label", headerText = nombre repetido), no plano como se asumio al
// principio (el golden set original solo tenia texto sin formato para este
// cover, sin negrita real capturada todavia) -- por eso hace falta cubrir
// AMBOS casos:
//   - sin negrita: un unico bloque "flat" con el nombre como su primera
//     linea (splitBulletsFromCellText ya lo cubria asi antes de este
//     parser).
//   - con negrita: un bloque "label"/"dash"/"value" cuyo headerText ES el
//     nombre repetido -- se descarta la cabecera y el bloque pasa a "flat"
//     con sus lineas propias intactas (mismo resultado final que el caso
//     sin negrita).
// Solo se descarta si queda contenido real debajo (nunca vaciar del todo
// una celda que sea unicamente el nombre repetido).
function stripLeadingCoverNameLine(blocks, coverName) {
  if (!coverName || blocks.length === 0) return blocks;
  const [first, ...rest] = blocks;
  const normalizedCoverName = coverName.toLowerCase();

  if (first.kind === "flat") {
    if (first.lines.length <= 1) return blocks;
    if (first.lines[0].toLowerCase() !== normalizedCoverName) return blocks;
    return [{ ...first, lines: first.lines.slice(1) }, ...rest];
  }

  if (first.headerText && first.lines.length > 0 && first.headerText.toLowerCase() === normalizedCoverName) {
    return [{ kind: "flat", headerText: null, lines: first.lines, needsReview: first.needsReview, reviewReason: first.reviewReason }, ...rest];
  }

  return blocks;
}

// Bloques reales de una celda de "Coberturas por modalidad" (ver
// rich_text_block_parser.js), filtrando el marcador "Garantía Opcional" -- ya
// sea como cabecera de un bloque entero o como una de sus lineas -- con el
// mismo criterio que isGarantiaOpcionalMarker aplicaba a bullets planos, y
// el nombre de cobertura repetido en celdas sin negrita (ver
// stripLeadingCoverNameLine).
function blocksFromCell(cell, coverName) {
  const { blocks } = parseModalityCellBlocks(cell || {});
  // El nombre de cobertura se descarta ANTES del marcador -- si se hiciera al
  // reves, una celda "NombreCobertura\nGarantía Opcional" perderia primero la
  // linea del marcador (quedando solo 1 linea) y ya no cumpliria el guard de
  // "mas de 1 linea" de stripLeadingCoverNameLine, dejando el nombre repetido
  // sin descartar (bug real detectado validando EFB-FIX-002 tras el cambio).
  const withoutCoverName = stripLeadingCoverNameLine(blocks, coverName);
  return withoutCoverName
    .map(b => ({ ...b, lines: (b.lines || []).filter(l => !isGarantiaOpcionalMarker(l)) }))
    .filter(b => !(b.headerText && isGarantiaOpcionalMarker(b.headerText)))
    // Si el marcador era la UNICA linea de un bloque "flat" (celda sin
    // negrita -- caso hipotetico, en los datos reales el marcador siempre
    // viene en negrita y se filtra arriba por headerText), el filtro de
    // lineas de arriba lo deja vacio (0 lineas, sin headerText) pero no lo
    // elimina -- se descarta aqui explicitamente. Un bloque "value" (0
    // lineas por diseno, ej. Capital) nunca se descarta porque SI tiene
    // headerText.
    .filter(b => b.headerText || (b.lines && b.lines.length > 0));
}

// Fallback para cuando el NUMERO de bloques difiere entre modalidades (caso
// real confirmado: COVER_ID 15 "RC" entre sus 11 modalidades completas -- es
// habitual y esperado que un paquete comercial superior incluya garantias
// enteras que el basico no tiene, decision del usuario 21/07: esto no
// deberia bloquear la generacion). Sin una posicion comun que alinear, el
// criterio pasa a ser CONTENIDO: un bloque (cabecera+lineas, normalizado)
// que aparece en TODAS las modalidades presentes es compartido
// (defaultBlocks, sin PRODUCT_COMPANY_MODALITY_ID); el resto se agrupa por
// contenido EXACTO, con groupIndex compartido entre variantes (para que una
// dependencia extraida en una de ellas se aplique a las demas via
// matchDependenciesToBlockGroups). Bloques de contenido UNICO quedan cada
// uno en su propia familia -- mismo criterio de "nunca alinear a la fuerza"
// que el resto del proyecto.
function buildBlockGroupsForHeterogeneousCover(coverId, coverName, blocksByModality) {
  const modalityIds = Object.keys(blocksByModality);
  const normalizedSetPerModality = {};
  for (const id of modalityIds) {
    normalizedSetPerModality[id] = new Set(blocksByModality[id].map(serializeBlockForComparison));
  }

  const defaultBlocks = [];
  const isDefault = new Set();
  for (const id of modalityIds) {
    for (const block of blocksByModality[id]) {
      const key = serializeBlockForComparison(block);
      if (isDefault.has(key)) continue;
      const inAllModalities = modalityIds.every(otherId => normalizedSetPerModality[otherId].has(key));
      if (inAllModalities) {
        defaultBlocks.push(block);
        isDefault.add(key);
      }
    }
  }

  const perModalityBlocks = [];
  const groupIndexByKey = new Map();
  let nextGroupIndex = 0;
  for (const id of modalityIds) {
    blocksByModality[id].forEach((block, blockIndex) => {
      const key = serializeBlockForComparison(block);
      if (isDefault.has(key)) return;
      if (!groupIndexByKey.has(key)) {
        groupIndexByKey.set(key, nextGroupIndex++);
      }
      perModalityBlocks.push({ modalityId: id, block, groupIndex: groupIndexByKey.get(key), blockIndex });
    });
  }

  return { coverId, coverName, homogeneous: true, defaultBlocks, perModalityBlocks };
}

// A16: agrupa los bloques de una cobertura segun si su contenido es
// identico en TODAS las modalidades (comparten un unico bloque sin
// PRODUCT_COMPANY_MODALITY_ID) o varia por modalidad (un bloque por
// modality_id). Alineacion por POSICION dentro de cada celda ya parseada en
// bloques cuando todas las modalidades presentes tienen el MISMO numero de
// bloques (necesario para casos como "Fontanería sin daños" donde el texto
// varia -- importe -- pero la posicion es la misma garantia real). Cuando
// el numero de bloques difiere entre modalidades, delega en
// buildBlockGroupsForHeterogeneousCover (ver arriba).
function buildBlockGroupsForCover(coverId, coverName, modalitiesMap) {
  const modalityIds = Object.keys(modalitiesMap || {});
  const blocksByModality = {};
  for (const modalityId of modalityIds) {
    blocksByModality[modalityId] = blocksFromCell(modalitiesMap[modalityId], coverName);
  }

  const counts = new Set(modalityIds.map(id => blocksByModality[id].length));
  if (counts.size > 1) {
    return buildBlockGroupsForHeterogeneousCover(coverId, coverName, blocksByModality);
  }

  const blockCount = modalityIds.length === 0 ? 0 : blocksByModality[modalityIds[0]].length;
  const defaultBlocks = [];
  const perModalityBlocks = [];
  for (let i = 0; i < blockCount; i++) {
    const blocksAtPosition = modalityIds.map(id => blocksByModality[id][i]);
    const keysAtPosition = blocksAtPosition.map(serializeBlockForComparison);
    const allSame = keysAtPosition.every(k => k === keysAtPosition[0]);
    if (allSame) {
      defaultBlocks.push(blocksAtPosition[0]);
    } else {
      modalityIds.forEach((id, idx) => {
        perModalityBlocks.push({ modalityId: id, block: blocksAtPosition[idx], groupIndex: i, blockIndex: i });
      });
    }
  }

  return { coverId, coverName, homogeneous: true, defaultBlocks, perModalityBlocks };
}

function findDependenciesForText(text, matches, coverId) {
  if (!text) return null;
  const bulletNormalized = normalize(text);
  const hit = (matches || []).find(
    m => m.cover_id === coverId && normalize(m.excel_quote || m.bullet_match || "") === bulletNormalized
  );
  return hit ? (hit.dependencies_translated || []) : null;
}

// Reconstruye {headerDependencies, lineDependencies} a partir de un array
// PLANO de dependencias por segmento (mismo orden que segmentTextsOf) --
// inverso de "aplanar" un bloque a sus segmentos, usado cuando las
// dependencias se resolvieron a nivel de familia (ver
// matchDependenciesToBlockGroups) en vez de directamente sobre el bloque.
function unflattenSegmentDependencies(block, segmentDependencies) {
  if (block.kind === "value") {
    return { headerDependencies: segmentDependencies[0] ?? null, lineDependencies: [] };
  }
  if (block.kind === "flat") {
    return { headerDependencies: null, lineDependencies: segmentDependencies };
  }
  const hasHeader = !!block.headerText;
  return {
    headerDependencies: hasHeader ? (segmentDependencies[0] ?? null) : null,
    lineDependencies: hasHeader ? segmentDependencies.slice(1) : segmentDependencies
  };
}

// Empareja la cita literal de cada dependencia (excel_quote/bullet_match)
// contra CADA segmento del bloque por separado (su cabecera y cada una de
// sus lineas), nunca contra el bloque entero -- un bloque puede agrupar
// varias lineas bajo una misma ENTRY, y solo UNA de ellas puede tener una
// condicion real (ver
// generator.buildBlockLines: cada dependencia se aplica a su LINE, nunca al
// FILTER_EXPR del ENTRY completo, para no ocultar de mas las lineas sin
// relacion). Empareja el bloque SOLO contra su propio texto -- sin mirar
// otras modalidades -- por eso es seguro de usar siempre, a diferencia de
// matchDependenciesToBlockGroups (ver abajo) cuando las formas no coinciden.
function matchDependenciesForBlock(block, matches, coverId) {
  const segments = segmentTextsOf(block);
  const segmentDependencies = segments.map(text => findDependenciesForText(text, matches, coverId));
  return unflattenSegmentDependencies(block, segmentDependencies);
}

// Aplica matchDependenciesForBlock a los bloques ya compartidos (sin
// PRODUCT_COMPANY_MODALITY_ID) que produce buildBlockGroupsForCover/
// buildBlockGroupsForHeterogeneousCover en su campo defaultBlocks.
function matchDependenciesToDefaultBlocks(defaultBlocks, matches, coverId) {
  return (defaultBlocks || []).map(block => ({ block, ...matchDependenciesForBlock(block, matches, coverId) }));
}

// Empareja dependencias para las familias de bloques (perModalityBlocks, ver
// buildBlockGroupsForCover/buildBlockGroupsForHeterogeneousCover), aplicando
// la MISMA dependencia a TODAS las variantes de una familia en cuanto UNA de
// ellas cita literalmente el texto (mismo espiritu que el fix real de
// COVER_ID 18 "Fontaneria sin daños" -- importe variable, condicion comun).
//
// Una familia por CONTENIDO EXACTO (rama heterogenea) tiene todos sus
// miembros identicos por construccion -- ahi da igual emparejar cada uno
// por separado o compartir el resultado, es lo mismo.
//
// Una familia por POSICION (rama homogenea, cuando el contenido difiere en
// la misma posicion -- ej. "Fontaneria sin danos" con el importe variando
// por modalidad) puede tener miembros con DISTINTO NUMERO de segmentos
// internos (caso real confirmado: COVER_ID 16 "Robo", su unico bloque tiene
// 7 lineas en las modalidades altas y solo 4 en la mas basica, aunque el
// CELDA entera cuenta como "1 bloque" en las 11). Aplicar una dependencia
// encontrada en el segmento N de una variante al segmento N de otra con
// menos segmentos no es seguro -- no hay garantia de que sea la misma
// garantia real. Por eso: si TODOS los miembros de la familia tienen el
// MISMO numero de segmentos, se busca la dependencia en cualquiera de ellos
// y se aplica por posicion a todos. Si no, cada miembro se empareja SOLO
// contra su propio texto (matchDependenciesForBlock) -- limitacion conocida
// y deliberada, no se fuerza una correspondencia sin garantia real.
function matchDependenciesToBlockGroups(perModalityBlocks, matches, coverId) {
  const byGroupIndex = new Map();
  for (const entry of perModalityBlocks || []) {
    const key = entry.groupIndex;
    if (!byGroupIndex.has(key)) byGroupIndex.set(key, []);
    byGroupIndex.get(key).push(entry);
  }

  const result = [];
  for (const family of byGroupIndex.values()) {
    const segmentCounts = new Set(family.map(({ block }) => segmentTextsOf(block).length));
    const sameShape = segmentCounts.size <= 1;

    if (!sameShape) {
      for (const { modalityId, block, blockIndex } of family) {
        result.push({ block, modalityId, blockIndex, ...matchDependenciesForBlock(block, matches, coverId) });
      }
      continue;
    }

    const segmentCount = segmentTextsOf(family[0].block).length;
    const segmentDependencies = Array.from({ length: segmentCount }, (_, segIdx) => {
      for (const { block } of family) {
        const hit = findDependenciesForText(segmentTextsOf(block)[segIdx], matches, coverId);
        if (hit) return hit;
      }
      return null;
    });

    for (const { modalityId, block, blockIndex } of family) {
      result.push({ block, modalityId, blockIndex, ...unflattenSegmentDependencies(block, segmentDependencies) });
    }
  }
  return result;
}

// --- adaptador n8n (nodo A16) ---
// Agrupa los BLOQUES (negrita/"-", ver rich_text_block_parser.js) de CADA
// cobertura por si varian entre modalidades, y adjunta las dependencias ya
// traducidas de "Translate Dependency Values" emparejando por SEGMENTO
// (cabecera o linea concreta dentro del bloque, ver
// matchDependenciesForBlock/matchDependenciesToDefaultBlocks/
// matchDependenciesToBlockGroups) -- nunca al bloque completo, para no
// aplicar una condicion real a lineas sin relacion dentro del mismo ENTRY.
// buildBlockGroupsForHeterogeneousCover (numero de bloques distinto entre
// modalidades) nunca bloquea la generacion (decision del usuario 21/07):
// siempre devuelve defaultBlocks/perModalityBlocks, sin caso "homogeneous:
// false" que marcar aparte.
const modalityCovers = $("Clean covers and modalities").all().map(i => i.json);
const matches = $("Translate Dependency Values").all().map(i => i.json).filter(m => m.decision === "match");

return modalityCovers.map(cover => {
  const groups = buildBlockGroupsForCover(cover.cover_id, cover.cover_name, cover.modalities);
  const defaultBlocks = matchDependenciesToDefaultBlocks(groups.defaultBlocks, matches, cover.cover_id);
  const conditionedBlocks = matchDependenciesToBlockGroups(groups.perModalityBlocks, matches, cover.cover_id);
  return {
    json: {
      coverId: cover.cover_id,
      coverName: cover.cover_name,
      defaultBlocks,
      conditionedBlocks,
      presentModalityIds: Object.keys(cover.modalities),
      allModalityIds: cover.all_modality_ids || []
    }
  };
});

// Ported pattern de "build agents context" (legacy). Alcance confirmado por
// el usuario (20/07): el matching texto->tuning_key en "Coberturas por
// modalidad" se limita a bullets literales "Garantia Opcional" -- no se
// corre sobre todos los bullets de esa hoja.
//
// Adaptado 22/07: cover.modalities ya no son strings de texto plano -- son
// celdas ricas de Google Sheets ({formattedValue, textFormatRuns,
// effectiveFormat}, ver rich_text_block_parser.js), porque "Covers by
// modality" ahora trae negrita real. Se usa formattedValue para la misma
// deteccion de texto de siempre.
const modalityCovers = $("Clean covers and modalities").all().map(i => i.json);
const optionalCovers = $("Clean Optional Covers").all().map(i => i.json);
const tuningRaw = $("Read Tuning Dictionary").first().json;
const tuningDictionary = tuningRaw.data ? tuningRaw.data : tuningRaw;
const tuningSimplified = Object.keys(tuningDictionary).map(key => ({
  key,
  label: (tuningDictionary[key] && tuningDictionary[key].label) ? tuningDictionary[key].label : "Sin etiqueta"
}));

const modalitiesNeedingTuning = [];
for (const cover of modalityCovers) {
  for (const cell of Object.values(cover.modalities || {})) {
    const cellText = (cell && cell.formattedValue) || "";
    if (cellText.split("\n").some(line => line.trim().toLowerCase() === "garantía opcional")) {
      modalitiesNeedingTuning.push({ cover_id: cover.cover_id, cover_name: cover.cover_name });
      break;
    }
  }
}

return [{
  json: {
    context: {
      data: {
        modalities: modalitiesNeedingTuning,
        optionals: optionalCovers,
        tuning: tuningSimplified
      }
    },
    tuningDictionary
  }
}];

// Guardrails y ensamblado del JSON intermedio revisable por humano (nodos
// A13 "Grounding Guardrail", A19 "Tuning Key Guardrail", A21 "Assemble
// Human-Review JSON" y B3 "Validate Review Completeness" del diseño de Fase
// 4 -- ver plan zippy-weaving-crown.md). Codigo puro, se valida offline
// (run_offline_eval.js, check --review-assembly) antes de construir los
// nodos n8n reales.


// A13: verifica que la decision del LLM de matching (Coverage Match Decision
// Agent) no alucine -- (a) el cover_id elegido debe estar entre los
// candidatos ofrecidos, (b) el excel_quote debe ser substring real
// (normalizado) del texto completo de ese candidato (`cover_full_text`,
// mismo campo que ya construye matcher.buildCandidateIndex). Si falla
// cualquiera, degrada la confianza a "baja" -- nunca descarta en silencio,
// mismo patron de visibilidad que el resto de guardrails del proyecto.
function applyGroundingGuardrail(llmDecision, candidates) {
  if (llmDecision.decision !== "match") {
    return { ...llmDecision, grounding_ok: true };
  }

  const candidate = (candidates || []).find(c => c.cover_id === llmDecision.cover_id);
  if (!candidate) {
    return { ...llmDecision, grounding_ok: false, confidence: "baja", degradation_reason: "cover_id_not_in_candidates" };
  }

  const quoteOk = !!llmDecision.excel_quote &&
    normalize(candidate.cover_full_text || "").includes(normalize(llmDecision.excel_quote));
  if (!quoteOk) {
    return { ...llmDecision, grounding_ok: false, confidence: "baja", degradation_reason: "excel_quote_not_grounded" };
  }

  return { ...llmDecision, grounding_ok: true };
}

// A19: valida que el tuning_key devuelto por el Tuning Key Mapping Agent
// exista realmente en el diccionario de tuning de esa compania, o sea
// "NOT_FOUND" explicito (ya senalado como pendiente en
// tuning_key_matcher_prompt.md). Un tuning_key inventado se degrada a
// NOT_FOUND en vez de colarse en el FILTER_EXPR/HIRING_STATUS_EXPR final.
function applyTuningKeyGuardrail(tuningKey, tuningDictionary) {
  if (tuningKey === "NOT_FOUND") {
    return { tuning_key: "NOT_FOUND", valid: true };
  }
  if (tuningDictionary && Object.prototype.hasOwnProperty.call(tuningDictionary, tuningKey)) {
    return { tuning_key: tuningKey, valid: true };
  }
  return { tuning_key: "NOT_FOUND", valid: false, original_tuning_key: tuningKey, reason: "tuning_key_not_in_dictionary" };
}

// Determina si una entrada necesita revision humana (esquema del JSON
// intermedio, ver plan Fase 4): confianza de matching distinta de "alta",
// grounding fallido, o traduccion de valor de enum parcial
// (value_matcher.translateDependencyValue con fullyTranslated: false).
function computeEntryReviewStatus(entry) {
  const reasons = [];
  if (entry.match && entry.match.confidence && entry.match.confidence !== "alta") {
    reasons.push("match_confidence_not_alta");
  }
  if (entry.match && entry.match.grounding_ok === false) {
    reasons.push("grounding_failed");
  }
  if (entry.value_translation && entry.value_translation.fully_translated === false) {
    reasons.push("value_translation_partial");
  }
  return {
    review_status: reasons.length > 0 ? "needs_review" : "auto_approved",
    review_reasons: reasons
  };
}

// A21: ensambla el JSON intermedio final a partir de los registros por
// cobertura ya generados (generator.buildEntriesForCover + metadatos de
// matching/traduccion/tuning adjuntos a cada entry). coverRecords:
// [{coverId, coverName, coverOverride, entries: [{entry_source, bullet_text,
// modality_id, match, dependencies_raw, dependencies_translated,
// value_translation, filter_expr, hiring_status_expr, value_expr,
// tuning_key, human_decision}]}].
function assembleHumanReviewJson({ productCompanyId, ramo, sourceFlow2Artifact, sourceExcel, coverRecords, unmatchedDependencies }) {
  const covers = (coverRecords || []).map(cover => {
    const entries = (cover.entries || []).map(entry => {
      const { review_status, review_reasons } = computeEntryReviewStatus(entry);
      return { ...entry, review_status, review_reasons, human_decision: entry.human_decision ?? null };
    });
    const coverReviewStatus = entries.some(e => e.review_status === "needs_review") ? "needs_review" : "auto_approved";
    return {
      cover_id: cover.coverId,
      cover_name: cover.coverName,
      cover_override_hiring_status_expr: cover.coverOverride ?? null,
      review_status: coverReviewStatus,
      entries
    };
  });

  const totalEntries = covers.reduce((sum, c) => sum + c.entries.length, 0);
  const entriesNeedingReview = covers.reduce(
    (sum, c) => sum + c.entries.filter(e => e.review_status === "needs_review").length,
    0
  );

  return {
    schema_version: "1.0",
    product_company_id: productCompanyId,
    ramo,
    source_flow2_artifact: sourceFlow2Artifact,
    source_excel: sourceExcel,
    summary: {
      total_covers: covers.length,
      covers_needing_review: covers.filter(c => c.review_status === "needs_review").length,
      total_entries: totalEntries,
      entries_needing_review: entriesNeedingReview
    },
    covers,
    unmatched_dependencies: unmatchedDependencies || []
  };
}

// B3: aborta con item de error explicito (nunca rubber-stamp) si queda
// alguna entrada needs_review sin human_decision.action relleno.
function validateReviewCompleteness(reviewJson) {
  const pending = [];
  for (const cover of reviewJson.covers || []) {
    for (const entry of cover.entries || []) {
      if (entry.review_status === "needs_review" && !(entry.human_decision && entry.human_decision.action)) {
        pending.push({ cover_id: cover.cover_id, bullet_text: entry.bullet_text });
      }
    }
  }
  return { complete: pending.length === 0, pending };
}

// Matcher offline dependencia (flujo 2) -> COVER_ID/bullet del Excel de coberturas.
//
// Este modulo implementa SOLO la parte determinista/heuristica del matcher
// (candidatos por similitud lexica + verificacion de grounding). La decision
// final en produccion la toma un LLM con estos candidatos como contexto (ver
// plan de flujo 3) -- aqui no se llama a ningun LLM, es la capa que se valida
// offline antes de construir el nodo n8n real (CLAUDE.md SS7).
//
// Cuando se construya el workflow n8n de flujo 3 (Fase 4 del plan), el codigo
// de esta funcion debe copiarse (o extraerse, siguiendo el mismo patron que
// evaluators/coverage_dependency_extractor/run_offline_eval.js) al Code node
// real que genera los candidatos antes de la llamada LLM.

const STOPWORDS = new Set([
  "de","la","el","los","las","en","y","o","del","con","por","para","que",
  "un","una","al","su","sus","a","e","u","es","se","lo","como","no","si",
  "the","of"
]);

function normalize(str) {
  return (str || "")
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[̀-ͯ]/g, "") // quitar acentos
    .replace(/^[\d]+(\.[\d]+)*\.?\s*/,"") // quitar numeracion inicial "3.2. "
    .replace(/^[a-z]\)\s*/,"") // quitar numeracion tipo "a) "
    .replace(/^articulo\s+[\wº.]+\s*/,"") // quitar "Articulo 8º "
    .replace(/[^a-z0-9\s]/g," ")
    .replace(/\s+/g," ")
    .trim();
}

function tokenize(str) {
  return normalize(str)
    .split(" ")
    .filter(tok => tok.length > 0 && !STOPWORDS.has(tok));
}

function jaccard(tokensA, tokensB) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  let intersection = 0;
  for (const tok of setA) if (setB.has(tok)) intersection++;
  const union = new Set([...setA, ...setB]).size;
  return intersection / union;
}

// Jaccard ponderado por rareza (idf-like): una palabra que aparece en pocos
// candidatos del indice (p. ej. "plagas") pesa mucho mas que una que aparece
// en casi todos (p. ej. "asistencia", "daños", "robo" -- genericas del dominio
// asegurador). Sin esto, una etiqueta estructural corta y generica (p. ej.
// "Asistencia") puede ganarle a un match especifico y correcto por pura
// coincidencia de una sola palabra comun (caso real detectado: GD-MATCH-025).
function weightedJaccard(tokensA, tokensB, idf) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  const all = new Set([...setA, ...setB]);
  let intersection = 0;
  let union = 0;
  for (const tok of all) {
    const w = idf.get(tok) || 1;
    union += w;
    if (setA.has(tok) && setB.has(tok)) intersection += w;
  }
  return union === 0 ? 0 : intersection / union;
}

// Frecuencia de documento inversa sobre los textos del indice de candidatos:
// cuantos menos candidatos contienen una palabra, mas discriminante es.
function buildIdf(candidateIndex) {
  const docFreq = new Map();
  const totalDocs = candidateIndex.length || 1;
  for (const candidate of candidateIndex) {
    const uniqueTokens = new Set(tokenize(candidate.text));
    for (const tok of uniqueTokens) docFreq.set(tok, (docFreq.get(tok) || 0) + 1);
  }
  const idf = new Map();
  for (const [tok, df] of docFreq) idf.set(tok, Math.log((totalDocs + 1) / (df + 1)) + 1);
  return idf;
}

// Construye el indice plano de candidatos (cover_id + texto) a partir del
// fixture normalizado del Excel (ambas hojas). Cada candidato lleva ademas
// `cover_full_text` (nombre + todos los bullets de esa cobertura) para el
// guardrail de grounding -- la evidencia de una dependencia describe la
// condicion, no necesariamente repite las palabras del bullet exacto, asi que
// el grounding se comprueba contra el contenido completo de la cobertura, no
// solo el fragmento que gano el matching.
function buildCandidateIndex(excelFixture) {
  const index = [];
  const byCoverName = new Map();
  const fullTextByCoverId = new Map();

  for (const cover of excelFixture.covers_por_modalidad || []) {
    byCoverName.set(normalize(cover.cover_name), cover.cover_id);
    fullTextByCoverId.set(
      cover.cover_id,
      [cover.cover_name, ...(cover.sample_text_bullets || [])].join(" ")
    );
  }
  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    if (parentCoverId != null) {
      fullTextByCoverId.set(
        parentCoverId,
        (fullTextByCoverId.get(parentCoverId) || "") + " " + opt.cover_name + " " + (opt.text_content || "")
      );
    }
  }

  for (const cover of excelFixture.covers_por_modalidad || []) {
    index.push({
      cover_id: cover.cover_id,
      text: cover.cover_name,
      cover_full_text: fullTextByCoverId.get(cover.cover_id) || cover.cover_name,
      source: "modality_cover_name"
    });
    for (const bullet of cover.sample_text_bullets || []) {
      index.push({
        cover_id: cover.cover_id,
        text: bullet,
        cover_full_text: fullTextByCoverId.get(cover.cover_id) || bullet,
        source: "modality_bullet"
      });
    }
  }

  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    index.push({
      cover_id: parentCoverId,
      text: opt.cover_name,
      cover_full_text: fullTextByCoverId.get(parentCoverId) || opt.cover_name,
      source: "optional_cover_name",
      exact_optional_name: normalize(opt.cover_name)
    });
  }

  return index;
}

const CONFIDENCE_THRESHOLDS = { alta: 0.55, media: 0.3 };

function confidenceLevel(score) {
  if (score >= CONFIDENCE_THRESHOLDS.alta) return "alta";
  if (score >= CONFIDENCE_THRESHOLDS.media) return "media";
  return "sin_match";
}

// coveragePath: array de strings (jerarquia interna del condicionado, la
// produce el flujo 2). article: titulo del articulo (fallback quando
// coverage_path viene vacio). evidenceText: texto real de la dependencia/
// evidencia (source_text o evidence concatenada) -- necesario porque la
// etiqueta estructural (coverage_path/article) puede ser enganosa (caso real:
// "Articulo 9 Asistencia" que en realidad habla de control de plagas, ver
// golden set GD-MATCH-025) y el contenido real desempata correctamente.
function matchDependency(coveragePath, article, evidenceText, candidateIndex) {
  const leafText = (coveragePath || [])[coveragePath.length - 1] || "";
  const leafNormalized = normalize(leafText);
  const leafTokens = tokenize(leafText);
  const rootText = (coveragePath || [])[0] || "";
  const rootNormalized = normalize(rootText);
  const rootTokens = tokenize(rootText + " " + (article || ""));
  const evidenceTokens = tokenize(evidenceText || "");
  const idf = buildIdf(candidateIndex);

  const scored = candidateIndex.map(candidate => {
    // Match exacto por nombre (hoja "Coberturas opcionales" -> join directo,
    // sin necesidad de similitud difusa). El nombre de la opcional puede
    // corresponder tanto al nivel hoja como al nivel raiz de coverage_path
    // (el desglose interno del condicionado no siempre alinea sus niveles con
    // el nombre exacto de la opcional en el mismo nivel).
    if (candidate.exact_optional_name &&
        (candidate.exact_optional_name === leafNormalized || candidate.exact_optional_name === rootNormalized)) {
      return { ...candidate, score: 1.0, match_type: "exact_optional_name" };
    }
    const candidateTokens = tokenize(candidate.text);
    const leafScore = weightedJaccard(leafTokens, candidateTokens, idf);
    const rootScore = weightedJaccard(rootTokens, candidateTokens, idf);
    const evidenceScore = weightedJaccard(evidenceTokens, candidateTokens, idf);
    // El nivel hoja (bullet concreto) es la senal mas especifica; el texto
    // real de la evidencia puede desempatar o corregir cuando la etiqueta
    // estructural es enganosa (palabras raras como "plagas" pesan mucho mas
    // que genericas como "asistencia" gracias al idf); el nivel raiz solo
    // ayuda para candidatos de nombre de cobertura completo.
    const score = Math.max(leafScore, evidenceScore * 0.9, rootScore * 0.8);
    return { ...candidate, score, match_type: "lexical" };
  });

  scored.sort((a, b) => b.score - a.score);
  const best = scored[0];
  if (!best || best.cover_id == null) {
    return { best: null, confidence: "sin_match", candidates: scored.slice(0, 5) };
  }

  return {
    best,
    confidence: confidenceLevel(best.score),
    candidates: scored.slice(0, 5)
  };
}

// Verifica que la evidencia citada tenga solape lexico real con el texto del
// bullet/cobertura emparejado -- guardrail de grounding (mismo espiritu que
// el guardrail de evidencia del flujo 2, aplicado aqui al texto del Excel en
// vez de al source_text del PDF).
function groundingScore(evidence, candidateText) {
  return jaccard(tokenize(evidence), tokenize(candidateText));
}

// --- adaptador n8n (nodo A19) ---
const mappings = $input.first().json.output.mappings;
const tuningDictionary = $("Build Tuning Context").first().json.tuningDictionary;
return mappings.map(m => ({
  json: { excel_name: m.excel_name, ...applyTuningKeyGuardrail(m.tuning_key, tuningDictionary) }
}));

// Generador de ENTRY/LINES (y su JSON intermedio) para una cobertura
// (COVER_ID), a partir de: el texto libre del Excel troceado en bullets, las
// dependencias ya emparejadas por matcher.js, y las reglas fijadas en
// knowledge/Modelo comparativa de coberturas - AI ready.md.
//
// Codigo puro (sin n8n, sin LLM) -- se valida offline (evaluators/
// coverage_insert_generator/run_offline_eval.js, check --generator) antes de
// construir el nodo n8n real (Fase 4 del plan, CLAUDE.md SS7).

const OPERATOR_TO_SPEL = {
  "=": "==",
  "!=": "!=",
  ">": ">",
  ">=": ">=",
  "<": "<",
  "<=": "<="
};

function quoteSpelValue(value) {
  if (typeof value === "string") {
    return `'${value.replace(/'/g, "\\'")}'`;
  }
  if (typeof value === "boolean" || typeof value === "number") {
    return String(value);
  }
  throw new Error(`Tipo de valor SPEL no soportado: ${typeof value} (${JSON.stringify(value)})`);
}

// Traduce una dependencia {risk_field, operator, value} (esquema del flujo 2)
// a una condicion SPEL sobre insurance["risk"]. Sintaxis de IN/NOT_IN
// corregida 24/07 (bug real detectado probando el motor real de ASM,
// Spring SpEL 5.3.39): SpEL no tiene operador `in` -- la sintaxis
// `campo in {v1,v2,v3}` usada originalmente no es valida en ese motor, hay
// que expresar la pertenencia como metodo de coleccion:
// `{v1,v2,v3}.contains(campo)` / `!{v1,v2,v3}.contains(campo)`.
function translateToSpel(dependency) {
  const field = `insurance["risk"].${dependency.risk_field}`;

  if (dependency.operator === "IN" || dependency.operator === "NOT_IN") {
    if (!Array.isArray(dependency.value)) {
      throw new Error(`operator ${dependency.operator} requiere value como array (dependency: ${JSON.stringify(dependency)})`);
    }
    const list = `{${dependency.value.map(quoteSpelValue).join(",")}}`;
    const membership = `${list}.contains(${field})`;
    return dependency.operator === "IN" ? membership : `!${membership}`;
  }

  const spelOp = OPERATOR_TO_SPEL[dependency.operator];
  if (!spelOp) {
    throw new Error(`Operador desconocido: ${dependency.operator}`);
  }
  return `${field} ${spelOp} ${quoteSpelValue(dependency.value)}`;
}

// Combina varias dependencias de un mismo ENTRY con AND. Con 1 sola
// dependencia no anade parentesis de mas.
function combineFilterExpr(dependencies) {
  if (!dependencies || dependencies.length === 0) return null;
  const parts = dependencies.map(translateToSpel);
  return parts.length === 1 ? parts[0] : parts.map(p => `(${p})`).join(" && ");
}

// Escapa un texto libre para usarlo como literal de cadena SPEL en TEXT_EXPR.
function spelStringLiteral(text) {
  return `'${(text || "").replace(/'/g, "\\'")}'`;
}

// Trocea el texto libre de una celda del Excel en bullets (una linea por
// bullet, ver knowledge/.../criterio de granularidad de LINES). Descarta la
// primera linea si es solo el nombre de la cobertura repetido (patron real
// observado: la celda empieza con el propio nombre a modo de cabecera).
function splitBulletsFromCellText(cellText, coverName) {
  const lines = (cellText || "")
    .split("\n")
    .map(l => l.trim())
    .filter(l => l.length > 0);
  if (lines.length > 1 && coverName && lines[0].toLowerCase() === coverName.toLowerCase()) {
    return lines.slice(1);
  }
  return lines;
}

// Construye los ENTRY/LINES de una cobertura completa.
//
// Input:
//   coverId, coverName
//   defaultBullets: string[] -- bullets sin ninguna dependencia estructural
//     emparejada (van todos en un unico ENTRY por defecto).
//   conditionedBullets: [{ text, dependencies, modalityId }] -- un ENTRY por
//     elemento (ver criterio de granularidad: ENTRY = condicion estructural).
//   opcionales: [{ coverName, textContent, hiringStatusExpr }] -- de la hoja
//     "Coberturas opcionales" ya resueltos a este cover_id.
//
// Output: { entries: [...], coverOverride: string|null }
// Traduce un bloque (salida de rich_text_block_parser.parseModalityCellBlocks,
// ver excel_fixture_builder.buildBlockGroupsForCover) a las LINES de su
// ENTRY, aplicando la dependencia de flow 2 que le corresponda a CADA
// segmento por separado (cabecera y cada linea, via
// excel_fixture_builder.matchDependenciesForBlock/matchDependenciesToBlockGroups)
// -- NUNCA al ENTRY completo. Motivo: un bloque puede agrupar varias lineas
// (ej. "-Responsabilidad Civil de la vivienda" con 4 lineas) donde solo UNA
// tiene una condicion real extraida del condicionado (ej. "Como inquilino
// frente al arrendador (locativa)" -> housingRegime == 'Tenant'); si esa
// condicion se pusiera en el FILTER_EXPR del ENTRY, ocultaria tambien las
// otras 3 lineas sin relacion. La cabecera (negrita o "-") se mantiene como
// primera linea visible -- ya se mostraba asi antes de este parser. Un
// bloque "value" (ej. "Capital 150.000€") no tiene cuerpo propio: su unica
// linea es el propio valor.
function buildBlockLines(block, headerDependencies, lineDependencies) {
  const lines = [];
  const pushLine = (text, dependencies) => {
    lines.push({ filter_expr: combineFilterExpr(dependencies), text_expr: spelStringLiteral(text) });
  };

  if (block.kind === "value") {
    pushLine(block.headerText, headerDependencies);
    return lines;
  }
  if (block.kind !== "flat" && block.headerText) {
    pushLine(block.headerText, headerDependencies);
  }
  (block.lines || []).forEach((text, i) => pushLine(text, (lineDependencies || [])[i]));
  return lines;
}

function buildEntriesForCover({
  coverId,
  coverName,
  defaultBullets = [],
  conditionedBullets = [],
  defaultBlocks = [],
  conditionedBlocks = [],
  opcionales = [],
  presentModalityIds = [],
  missingModalityIds = []
}) {
  const entries = [];

  if (defaultBullets.length > 0) {
    entries.push({
      cover_id: coverId,
      filter_expr: null,
      hiring_status_expr: '"INCLUDED"',
      value_expr: null,
      modality_id: null,
      source: "default",
      lines: defaultBullets.map(text => ({ filter_expr: null, text_expr: spelStringLiteral(text) }))
    });
  }

  for (const entry of defaultBlocks) {
    entries.push({
      cover_id: coverId,
      filter_expr: null,
      hiring_status_expr: '"INCLUDED"',
      value_expr: null,
      modality_id: null,
      source: "default",
      lines: buildBlockLines(entry.block, entry.headerDependencies, entry.lineDependencies)
    });
  }

  for (const bullet of conditionedBullets) {
    entries.push({
      cover_id: coverId,
      filter_expr: combineFilterExpr(bullet.dependencies),
      hiring_status_expr: '"INCLUDED"',
      value_expr: null,
      modality_id: bullet.modalityId ?? null,
      source: "modality_bullet",
      lines: [{ filter_expr: null, text_expr: spelStringLiteral(bullet.text) }]
    });
  }

  for (const cond of conditionedBlocks) {
    entries.push({
      cover_id: coverId,
      filter_expr: null,
      hiring_status_expr: '"INCLUDED"',
      value_expr: null,
      modality_id: cond.modalityId ?? null,
      source: "modality_bullet",
      lines: buildBlockLines(cond.block, cond.headerDependencies, cond.lineDependencies),
      _blockIndex: cond.blockIndex
    });
  }

  // Bug real corregido 22/07 (covers 79/81, "Sin cobertura" en varias
  // modalidades de "Coberturas por modalidad"): una cobertura opcional
  // (hoja "Coberturas opcionales") no tiene por que ofrecerse en TODAS las
  // modalidades de su cobertura base -- si "Coberturas por modalidad" dice
  // "Sin cobertura" para una modalidad concreta, esa modalidad no puede
  // contratar ni la base ni el opcional, y debe salir NOT_INCLUDED
  // explicito, no la formula de tuning (que antes se aplicaba por igual a
  // las 11 modalidades, modality_id null, ignorando cuales la ofrecen
  // realmente). Si NINGUNA modalidad falta (missingModalityIds vacio, caso
  // normal), se mantiene el comportamiento de siempre: una unica ENTRY sin
  // modalidad.
  for (const opt of opcionales) {
    const optLines = splitBulletsFromCellText(opt.textContent, null).map(text => ({ filter_expr: null, text_expr: spelStringLiteral(text) }));

    if (missingModalityIds.length === 0) {
      entries.push({
        cover_id: coverId,
        filter_expr: opt.filterExpr ?? null,
        hiring_status_expr: opt.hiringStatusExpr || '"OPTIONAL"',
        value_expr: null,
        modality_id: null,
        source: "optional_cover",
        lines: optLines
      });
      continue;
    }

    // Caso simetrico al de arriba: la cobertura opcional no esta disponible
    // en NINGUNA modalidad (presentModalityIds vacio) -- incluida la propia
    // cobertura base, no solo el opcional (bug real 24/07, cover 105
    // "Vehiculos/maq. autopropulsada en reposo"). Todas las entries
    // resultarian identicas (mismo NOT_INCLUDED, mismas 0 lineas) salvo por
    // el modality_id, asi que aplica la regla de optimizacion obligatoria
    // del modelo (Paso 2: mismos valores en todas las modalidades ->
    // PRODUCT_COMPANY_MODALITY_ID = NULL) -- una unica ENTRY, no una por
    // modalidad.
    if (presentModalityIds.length === 0) {
      entries.push({
        cover_id: coverId,
        filter_expr: null,
        hiring_status_expr: '"NOT_INCLUDED"',
        value_expr: null,
        modality_id: null,
        source: "optional_cover",
        lines: []
      });
      continue;
    }

    for (const modalityId of missingModalityIds) {
      entries.push({
        cover_id: coverId,
        filter_expr: null,
        hiring_status_expr: '"NOT_INCLUDED"',
        value_expr: null,
        modality_id: modalityId,
        source: "optional_cover",
        lines: []
      });
    }
    for (const modalityId of presentModalityIds) {
      entries.push({
        cover_id: coverId,
        filter_expr: opt.filterExpr ?? null,
        hiring_status_expr: opt.hiringStatusExpr || '"OPTIONAL"',
        value_expr: null,
        modality_id: modalityId,
        source: "optional_cover",
        lines: optLines
      });
    }
  }

  const coverOverride = computeCoverOverride(entries);
  if (coverOverride) {
    for (const entry of entries) {
      if (entry.filter_expr === coverOverride.sharedCondition) {
        entry.filter_expr = null;
      }
    }
  }

  const sorted = sortEntriesByModality(entries);
  sorted.forEach(entry => delete entry._blockIndex);

  return {
    entries: sorted,
    coverOverride: coverOverride ? coverOverride.hiringStatusExpr : null
  };
}

// Reordena las ENTRY para que sea facil revisar si una modalidad concreta
// tiene todo su contenido (peticion del usuario, 22/07 -- con el orden de
// construccion original, entries de la misma modalidad quedaban dispersas
// entre familias/bloques distintos). Primero las sin modalidad que vienen
// del propio Excel de modalidades (comunes a todas, source "default"),
// despues agrupadas por modalidad, y las de "Coberturas opcionales"
// (source "optional_cover") siempre al FINAL con independencia de que su
// modality_id sea null -- ajuste pedido por el usuario tras revisar un caso
// real (cover 15: "Responsabilidad civil por propiedad y tenencia de
// perros" salia antes que las entries por modalidad, dificultando revisar
// si una modalidad concreta tiene todo su contenido).
//
// Dentro de una MISMA modalidad, se ordena ademas por _blockIndex (la
// posicion original del bloque dentro de su propia celda, ver
// excel_fixture_builder.buildBlockGroupsForCover/Heterogeneous) -- bug real
// detectado 22/07 (cover 15): sin este criterio, el orden dentro de una
// modalidad dependia de en que momento se creaba el groupIndex de cada
// familia durante el agrupamiento (un artefacto interno de
// matchDependenciesToBlockGroups, no el orden real de la celda), asi que el
// Capital aparecia primero en unas modalidades y al final en otras.
// _blockIndex es un campo temporal (no forma parte del ENTRY final, ver el
// borrado tras ordenar en buildEntriesForCover) -- las entries que no vienen
// de conditionedBlocks (default/bullets/opcionales) no lo tienen, se tratan
// como 0 (no afecta su posicion relativa entre modalidades, solo el
// desempate DENTRO de la misma modalidad). Array.prototype.sort es estable
// en Node/V8, asi que el orden relativo dentro de un mismo (modalidad,
// blockIndex) se conserva tal cual las genero buildEntriesForCover.
function sortEntriesByModality(entries) {
  return [...entries].sort((a, b) => {
    const aIsOptional = a.source === "optional_cover" ? 1 : 0;
    const bIsOptional = b.source === "optional_cover" ? 1 : 0;
    if (aIsOptional !== bIsOptional) return aIsOptional - bIsOptional;
    const aKey = a.modality_id == null ? -Infinity : Number(a.modality_id);
    const bKey = b.modality_id == null ? -Infinity : Number(b.modality_id);
    if (aKey !== bKey) return aKey - bKey;
    return (a._blockIndex ?? 0) - (b._blockIndex ?? 0);
  });
}

// Construye el HIRING_STATUS_EXPR real (formula SPEL) de una cobertura
// opcional contratable via tuning, siguiendo el patron ya confirmado en
// knowledge/Modelo comparativa de coberturas - AI ready.md ("Ejemplo
// completo 2"): INCLUDED si el tuning tiene la opcion marcada, OPTIONAL si
// no. Sin un tuning_key real resuelto (NOT_FOUND) no hay forma de construir
// esa condicion -- se mantiene el literal "OPTIONAL" tal cual (mismo
// comportamiento que antes para ese caso).
function buildOptionalHiringStatusExpr(tuningKey) {
  if (!tuningKey || tuningKey === "NOT_FOUND") return '"OPTIONAL"';
  return `tuning?.${tuningKey} != null && tuning.${tuningKey} ? "INCLUDED" : "OPTIONAL"`;
}

// Regla de optimizacion: si TODOS los ENTRY (2 o mas) comparten exactamente
// la misma condicion no nula, se traslada al HIRING_STATUS_EXPR de
// PRODUCT_COMPANY_COVER en vez de repetirse en cada ENTRY (decision del
// usuario, opcion B: el contenido sigue visible aunque la cobertura salga
// NOT_INCLUDED). Con menos de 2 ENTRY no hay nada que deduplicar -- salvo el
// caso de 0 ENTRY (cobertura sin ningun bloque real): ahi se fuerza
// explicitamente NOT_INCLUDED (decision del usuario, 21/07) en vez de dejar
// NULL y depender de que el motor real agregue "cero bloques" a NOT_INCLUDED
// de forma implicita.
function computeCoverOverride(entries) {
  if (entries.length === 0) {
    return { sharedCondition: undefined, hiringStatusExpr: `"NOT_INCLUDED"` };
  }
  if (entries.length < 2) return null;
  const conditions = entries.map(e => e.filter_expr);
  if (conditions.some(c => c == null)) return null;
  const allSame = conditions.every(c => c === conditions[0]);
  if (!allSame) return null;
  return {
    sharedCondition: conditions[0],
    hiringStatusExpr: `${conditions[0]} ? "INCLUDED" : "NOT_INCLUDED"`
  };
}

// Generacion del SQL INSERT final (motor: MySQL, confirmado por el usuario)
// a partir del artefacto de una cobertura (ver buildEntriesForCover). Usa
// variables de sesion (`SET @var := LAST_INSERT_ID()`) para encadenar las FK
// entre PRODUCT_COMPANY_COVER -> _ENTRY -> _LINES, ya que los INSERT se
// ejecutan secuencialmente y el ID de cada fila se genera en la propia BBDD.
//
// Confirmado por el usuario (20/07): toda expresion SPEL (no solo TEXT_EXPR)
// lleva el envoltorio "/" ... "/" -- se aplica por igual a FILTER_EXPR/
// HIRING_STATUS_EXPR/VALUE_EXPR/TEXT_EXPR.
function wrapAsSpelExpression(rawExpr) {
  return rawExpr == null ? null : `/${rawExpr}/`;
}

// Literal SQL: escapa comillas simples con backslash, igual que el ejemplo
// real del modelo (`'/\'texto\'/'`) -- convencion de MySQL con
// NO_BACKSLASH_ESCAPES desactivado (el modo por defecto).
function sqlLiteral(value) {
  if (value == null) return "NULL";
  if (typeof value === "number") return String(value);
  return `'${String(value).replace(/'/g, "\\'")}'`;
}

// coverArtifact: { coverId, productCompanyId, coverOverride, entries } --
// coverOverride y entries.*.filter_expr/hiring_status_expr/value_expr son
// expresiones SPEL en crudo (sin el envoltorio "/.../"); entries.*.lines[].
// text_expr ya viene como literal de cadena SPEL (`'texto'`, ver
// spelStringLiteral) al que tambien hay que anadirle el envoltorio.
function buildInsertStatements({ coverId, productCompanyId, coverOverride, entries }) {
  const statements = [];

  statements.push(
    `INSERT INTO PRODUCT_COMPANY_COVER (HIRING_STATUS_EXPR, COVER_ID, PRODUCT_COMPANY_ID) VALUES (${sqlLiteral(wrapAsSpelExpression(coverOverride))}, ${coverId}, ${productCompanyId});`
  );
  statements.push("SET @cover_id := LAST_INSERT_ID();");

  entries.forEach((entry, entryIndex) => {
    const entryVar = `@entry_id_${entryIndex + 1}`;
    statements.push(
      `INSERT INTO PRODUCT_COMPANY_COVER_ENTRY (FILTER_EXPR, HIRING_STATUS_EXPR, ENTRY_ORDER, VALUE_EXPR, UNIT, PRODUCT_COMPANY_MODALITY_ID, PRODUCT_COMPANY_COVER_ID) VALUES (${sqlLiteral(wrapAsSpelExpression(entry.filter_expr))}, ${sqlLiteral(wrapAsSpelExpression(entry.hiring_status_expr))}, ${entryIndex + 1}, ${sqlLiteral(wrapAsSpelExpression(entry.value_expr))}, NULL, ${entry.modality_id ?? "NULL"}, @cover_id);`
    );
    statements.push(`SET ${entryVar} := LAST_INSERT_ID();`);

    entry.lines.forEach((line, lineIndex) => {
      statements.push(
        `INSERT INTO PRODUCT_COMPANY_COVER_LINES (FILTER_EXPR, TEXT_EXPR, PRODUCT_COMPANY_COVER_ENTRY_ID, LINE_ORDER) VALUES (${sqlLiteral(wrapAsSpelExpression(line.filter_expr))}, ${sqlLiteral(wrapAsSpelExpression(line.text_expr))}, ${entryVar}, ${lineIndex + 1});`
      );
    });
  });

  return statements;
}

// --- adaptador n8n (nodo A20) ---
// Combina los grupos de bloques por cobertura (A16) con las coberturas
// opcionales (A5) y el tuning_key resuelto (A19) para construir el
// artefacto ENTRY/LINES de cada COVER_ID via generator.buildEntriesForCover.
// El cruce opcional<->tuning_key por nombre exacto sigue siendo un primer
// borrador (sin cambios en esta ronda). Ya no existe el caso "homogeneous:
// false" (ver Build Per-Cover Bullet Groups) -- todas las coberturas llegan
// con defaultBlocks/conditionedBlocks reales.
const blockGroups = $("Build Per-Cover Bullet Groups").all().map(i => i.json);
const optionalCovers = $("Clean Optional Covers").all().map(i => i.json);
const tuningKeys = $("Tuning Key Guardrail").all().map(i => i.json);

function tuningKeyFor(excelName) {
  const hit = tuningKeys.find(t => t.excel_name === excelName);
  return hit ? hit.tuning_key : "NOT_FOUND";
}

return blockGroups.map(group => {
  const opcionalesDeCover = optionalCovers
    .filter(o => o.parent_cover_id === group.coverId)
    .map(o => {
      const tuningKey = tuningKeyFor(o.cover_name);
      return { coverName: o.cover_name, textContent: o.text_content, hiringStatusExpr: buildOptionalHiringStatusExpr(tuningKey), tuningKey };
    });

  const presentModalityIds = group.presentModalityIds || [];
  const missingModalityIds = (group.allModalityIds || []).filter(id => !presentModalityIds.includes(id));

  const { entries, coverOverride } = buildEntriesForCover({
    coverId: group.coverId,
    coverName: group.coverName,
    defaultBlocks: group.defaultBlocks,
    conditionedBlocks: group.conditionedBlocks,
    opcionales: opcionalesDeCover,
    presentModalityIds,
    missingModalityIds
  });

  return { json: { coverId: group.coverId, coverName: group.coverName, coverOverride, entries, needsReview: false, reviewReason: null } };
});

// Guardrails y ensamblado del JSON intermedio revisable por humano (nodos
// A13 "Grounding Guardrail", A19 "Tuning Key Guardrail", A21 "Assemble
// Human-Review JSON" y B3 "Validate Review Completeness" del diseño de Fase
// 4 -- ver plan zippy-weaving-crown.md). Codigo puro, se valida offline
// (run_offline_eval.js, check --review-assembly) antes de construir los
// nodos n8n reales.


// A13: verifica que la decision del LLM de matching (Coverage Match Decision
// Agent) no alucine -- (a) el cover_id elegido debe estar entre los
// candidatos ofrecidos, (b) el excel_quote debe ser substring real
// (normalizado) del texto completo de ese candidato (`cover_full_text`,
// mismo campo que ya construye matcher.buildCandidateIndex). Si falla
// cualquiera, degrada la confianza a "baja" -- nunca descarta en silencio,
// mismo patron de visibilidad que el resto de guardrails del proyecto.
function applyGroundingGuardrail(llmDecision, candidates) {
  if (llmDecision.decision !== "match") {
    return { ...llmDecision, grounding_ok: true };
  }

  const candidate = (candidates || []).find(c => c.cover_id === llmDecision.cover_id);
  if (!candidate) {
    return { ...llmDecision, grounding_ok: false, confidence: "baja", degradation_reason: "cover_id_not_in_candidates" };
  }

  const quoteOk = !!llmDecision.excel_quote &&
    normalize(candidate.cover_full_text || "").includes(normalize(llmDecision.excel_quote));
  if (!quoteOk) {
    return { ...llmDecision, grounding_ok: false, confidence: "baja", degradation_reason: "excel_quote_not_grounded" };
  }

  return { ...llmDecision, grounding_ok: true };
}

// A19: valida que el tuning_key devuelto por el Tuning Key Mapping Agent
// exista realmente en el diccionario de tuning de esa compania, o sea
// "NOT_FOUND" explicito (ya senalado como pendiente en
// tuning_key_matcher_prompt.md). Un tuning_key inventado se degrada a
// NOT_FOUND en vez de colarse en el FILTER_EXPR/HIRING_STATUS_EXPR final.
function applyTuningKeyGuardrail(tuningKey, tuningDictionary) {
  if (tuningKey === "NOT_FOUND") {
    return { tuning_key: "NOT_FOUND", valid: true };
  }
  if (tuningDictionary && Object.prototype.hasOwnProperty.call(tuningDictionary, tuningKey)) {
    return { tuning_key: tuningKey, valid: true };
  }
  return { tuning_key: "NOT_FOUND", valid: false, original_tuning_key: tuningKey, reason: "tuning_key_not_in_dictionary" };
}

// Determina si una entrada necesita revision humana (esquema del JSON
// intermedio, ver plan Fase 4): confianza de matching distinta de "alta",
// grounding fallido, o traduccion de valor de enum parcial
// (value_matcher.translateDependencyValue con fullyTranslated: false).
function computeEntryReviewStatus(entry) {
  const reasons = [];
  if (entry.match && entry.match.confidence && entry.match.confidence !== "alta") {
    reasons.push("match_confidence_not_alta");
  }
  if (entry.match && entry.match.grounding_ok === false) {
    reasons.push("grounding_failed");
  }
  if (entry.value_translation && entry.value_translation.fully_translated === false) {
    reasons.push("value_translation_partial");
  }
  return {
    review_status: reasons.length > 0 ? "needs_review" : "auto_approved",
    review_reasons: reasons
  };
}

// A21: ensambla el JSON intermedio final a partir de los registros por
// cobertura ya generados (generator.buildEntriesForCover + metadatos de
// matching/traduccion/tuning adjuntos a cada entry). coverRecords:
// [{coverId, coverName, coverOverride, entries: [{entry_source, bullet_text,
// modality_id, match, dependencies_raw, dependencies_translated,
// value_translation, filter_expr, hiring_status_expr, value_expr,
// tuning_key, human_decision}]}].
function assembleHumanReviewJson({ productCompanyId, ramo, sourceFlow2Artifact, sourceExcel, coverRecords, unmatchedDependencies }) {
  const covers = (coverRecords || []).map(cover => {
    const entries = (cover.entries || []).map(entry => {
      const { review_status, review_reasons } = computeEntryReviewStatus(entry);
      return { ...entry, review_status, review_reasons, human_decision: entry.human_decision ?? null };
    });
    const coverReviewReasons = cover.needsReview ? [cover.reviewReason || "structural_review_required"] : [];
    const coverReviewStatus = coverReviewReasons.length > 0 || entries.some(e => e.review_status === "needs_review")
      ? "needs_review"
      : "auto_approved";
    return {
      cover_id: cover.coverId,
      cover_name: cover.coverName,
      cover_override_hiring_status_expr: cover.coverOverride ?? null,
      review_status: coverReviewStatus,
      review_reasons: coverReviewReasons,
      entries
    };
  });

  const totalEntries = covers.reduce((sum, c) => sum + c.entries.length, 0);
  const entriesNeedingReview = covers.reduce(
    (sum, c) => sum + c.entries.filter(e => e.review_status === "needs_review").length,
    0
  );

  return {
    schema_version: "1.0",
    product_company_id: productCompanyId,
    ramo,
    source_flow2_artifact: sourceFlow2Artifact,
    source_excel: sourceExcel,
    summary: {
      total_covers: covers.length,
      covers_needing_review: covers.filter(c => c.review_status === "needs_review").length,
      total_entries: totalEntries,
      entries_needing_review: entriesNeedingReview
    },
    covers,
    unmatched_dependencies: unmatchedDependencies || []
  };
}

// B3: aborta con item de error explicito (nunca rubber-stamp) si queda
// alguna entrada needs_review sin human_decision.action relleno.
function validateReviewCompleteness(reviewJson) {
  const pending = [];
  for (const cover of reviewJson.covers || []) {
    for (const entry of cover.entries || []) {
      if (entry.review_status === "needs_review" && !(entry.human_decision && entry.human_decision.action)) {
        pending.push({ cover_id: cover.cover_id, bullet_text: entry.bullet_text });
      }
    }
  }
  return { complete: pending.length === 0, pending };
}

// Matcher offline dependencia (flujo 2) -> COVER_ID/bullet del Excel de coberturas.
//
// Este modulo implementa SOLO la parte determinista/heuristica del matcher
// (candidatos por similitud lexica + verificacion de grounding). La decision
// final en produccion la toma un LLM con estos candidatos como contexto (ver
// plan de flujo 3) -- aqui no se llama a ningun LLM, es la capa que se valida
// offline antes de construir el nodo n8n real (CLAUDE.md SS7).
//
// Cuando se construya el workflow n8n de flujo 3 (Fase 4 del plan), el codigo
// de esta funcion debe copiarse (o extraerse, siguiendo el mismo patron que
// evaluators/coverage_dependency_extractor/run_offline_eval.js) al Code node
// real que genera los candidatos antes de la llamada LLM.

const STOPWORDS = new Set([
  "de","la","el","los","las","en","y","o","del","con","por","para","que",
  "un","una","al","su","sus","a","e","u","es","se","lo","como","no","si",
  "the","of"
]);

function normalize(str) {
  return (str || "")
    .toString()
    .toLowerCase()
    .normalize("NFD")
    .replace(/[̀-ͯ]/g, "") // quitar acentos
    .replace(/^[\d]+(\.[\d]+)*\.?\s*/,"") // quitar numeracion inicial "3.2. "
    .replace(/^[a-z]\)\s*/,"") // quitar numeracion tipo "a) "
    .replace(/^articulo\s+[\wº.]+\s*/,"") // quitar "Articulo 8º "
    .replace(/[^a-z0-9\s]/g," ")
    .replace(/\s+/g," ")
    .trim();
}

function tokenize(str) {
  return normalize(str)
    .split(" ")
    .filter(tok => tok.length > 0 && !STOPWORDS.has(tok));
}

function jaccard(tokensA, tokensB) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  let intersection = 0;
  for (const tok of setA) if (setB.has(tok)) intersection++;
  const union = new Set([...setA, ...setB]).size;
  return intersection / union;
}

// Jaccard ponderado por rareza (idf-like): una palabra que aparece en pocos
// candidatos del indice (p. ej. "plagas") pesa mucho mas que una que aparece
// en casi todos (p. ej. "asistencia", "daños", "robo" -- genericas del dominio
// asegurador). Sin esto, una etiqueta estructural corta y generica (p. ej.
// "Asistencia") puede ganarle a un match especifico y correcto por pura
// coincidencia de una sola palabra comun (caso real detectado: GD-MATCH-025).
function weightedJaccard(tokensA, tokensB, idf) {
  const setA = new Set(tokensA);
  const setB = new Set(tokensB);
  if (setA.size === 0 || setB.size === 0) return 0;
  const all = new Set([...setA, ...setB]);
  let intersection = 0;
  let union = 0;
  for (const tok of all) {
    const w = idf.get(tok) || 1;
    union += w;
    if (setA.has(tok) && setB.has(tok)) intersection += w;
  }
  return union === 0 ? 0 : intersection / union;
}

// Frecuencia de documento inversa sobre los textos del indice de candidatos:
// cuantos menos candidatos contienen una palabra, mas discriminante es.
function buildIdf(candidateIndex) {
  const docFreq = new Map();
  const totalDocs = candidateIndex.length || 1;
  for (const candidate of candidateIndex) {
    const uniqueTokens = new Set(tokenize(candidate.text));
    for (const tok of uniqueTokens) docFreq.set(tok, (docFreq.get(tok) || 0) + 1);
  }
  const idf = new Map();
  for (const [tok, df] of docFreq) idf.set(tok, Math.log((totalDocs + 1) / (df + 1)) + 1);
  return idf;
}

// Construye el indice plano de candidatos (cover_id + texto) a partir del
// fixture normalizado del Excel (ambas hojas). Cada candidato lleva ademas
// `cover_full_text` (nombre + todos los bullets de esa cobertura) para el
// guardrail de grounding -- la evidencia de una dependencia describe la
// condicion, no necesariamente repite las palabras del bullet exacto, asi que
// el grounding se comprueba contra el contenido completo de la cobertura, no
// solo el fragmento que gano el matching.
function buildCandidateIndex(excelFixture) {
  const index = [];
  const byCoverName = new Map();
  const fullTextByCoverId = new Map();

  for (const cover of excelFixture.covers_por_modalidad || []) {
    byCoverName.set(normalize(cover.cover_name), cover.cover_id);
    fullTextByCoverId.set(
      cover.cover_id,
      [cover.cover_name, ...(cover.sample_text_bullets || [])].join(" ")
    );
  }
  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    if (parentCoverId != null) {
      fullTextByCoverId.set(
        parentCoverId,
        (fullTextByCoverId.get(parentCoverId) || "") + " " + opt.cover_name + " " + (opt.text_content || "")
      );
    }
  }

  for (const cover of excelFixture.covers_por_modalidad || []) {
    index.push({
      cover_id: cover.cover_id,
      text: cover.cover_name,
      cover_full_text: fullTextByCoverId.get(cover.cover_id) || cover.cover_name,
      source: "modality_cover_name"
    });
    for (const bullet of cover.sample_text_bullets || []) {
      index.push({
        cover_id: cover.cover_id,
        text: bullet,
        cover_full_text: fullTextByCoverId.get(cover.cover_id) || bullet,
        source: "modality_bullet"
      });
    }
  }

  for (const opt of excelFixture.coberturas_opcionales || []) {
    const parentCoverId = byCoverName.get(normalize(opt.epigrafe)) ?? null;
    index.push({
      cover_id: parentCoverId,
      text: opt.cover_name,
      cover_full_text: fullTextByCoverId.get(parentCoverId) || opt.cover_name,
      source: "optional_cover_name",
      exact_optional_name: normalize(opt.cover_name)
    });
  }

  return index;
}

const CONFIDENCE_THRESHOLDS = { alta: 0.55, media: 0.3 };

function confidenceLevel(score) {
  if (score >= CONFIDENCE_THRESHOLDS.alta) return "alta";
  if (score >= CONFIDENCE_THRESHOLDS.media) return "media";
  return "sin_match";
}

// coveragePath: array de strings (jerarquia interna del condicionado, la
// produce el flujo 2). article: titulo del articulo (fallback quando
// coverage_path viene vacio). evidenceText: texto real de la dependencia/
// evidencia (source_text o evidence concatenada) -- necesario porque la
// etiqueta estructural (coverage_path/article) puede ser enganosa (caso real:
// "Articulo 9 Asistencia" que en realidad habla de control de plagas, ver
// golden set GD-MATCH-025) y el contenido real desempata correctamente.
function matchDependency(coveragePath, article, evidenceText, candidateIndex) {
  const leafText = (coveragePath || [])[coveragePath.length - 1] || "";
  const leafNormalized = normalize(leafText);
  const leafTokens = tokenize(leafText);
  const rootText = (coveragePath || [])[0] || "";
  const rootNormalized = normalize(rootText);
  const rootTokens = tokenize(rootText + " " + (article || ""));
  const evidenceTokens = tokenize(evidenceText || "");
  const idf = buildIdf(candidateIndex);

  const scored = candidateIndex.map(candidate => {
    // Match exacto por nombre (hoja "Coberturas opcionales" -> join directo,
    // sin necesidad de similitud difusa). El nombre de la opcional puede
    // corresponder tanto al nivel hoja como al nivel raiz de coverage_path
    // (el desglose interno del condicionado no siempre alinea sus niveles con
    // el nombre exacto de la opcional en el mismo nivel).
    if (candidate.exact_optional_name &&
        (candidate.exact_optional_name === leafNormalized || candidate.exact_optional_name === rootNormalized)) {
      return { ...candidate, score: 1.0, match_type: "exact_optional_name" };
    }
    const candidateTokens = tokenize(candidate.text);
    const leafScore = weightedJaccard(leafTokens, candidateTokens, idf);
    const rootScore = weightedJaccard(rootTokens, candidateTokens, idf);
    const evidenceScore = weightedJaccard(evidenceTokens, candidateTokens, idf);
    // El nivel hoja (bullet concreto) es la senal mas especifica; el texto
    // real de la evidencia puede desempatar o corregir cuando la etiqueta
    // estructural es enganosa (palabras raras como "plagas" pesan mucho mas
    // que genericas como "asistencia" gracias al idf); el nivel raiz solo
    // ayuda para candidatos de nombre de cobertura completo.
    const score = Math.max(leafScore, evidenceScore * 0.9, rootScore * 0.8);
    return { ...candidate, score, match_type: "lexical" };
  });

  scored.sort((a, b) => b.score - a.score);
  const best = scored[0];
  if (!best || best.cover_id == null) {
    return { best: null, confidence: "sin_match", candidates: scored.slice(0, 5) };
  }

  return {
    best,
    confidence: confidenceLevel(best.score),
    candidates: scored.slice(0, 5)
  };
}

// Verifica que la evidencia citada tenga solape lexico real con el texto del
// bullet/cobertura emparejado -- guardrail de grounding (mismo espiritu que
// el guardrail de evidencia del flujo 2, aplicado aqui al texto del Excel en
// vez de al source_text del PDF).
function groundingScore(evidence, candidateText) {
  return jaccard(tokenize(evidence), tokenize(candidateText));
}

// --- adaptador n8n (nodo A21) ---
const formData = $("Borrador de comparativa - On form submission").first().json;
const coverRecords = $input.all().map(i => i.json);

const reviewJson = assembleHumanReviewJson({
  productCompanyId: formData["Product Company Id"],
  ramo: formData.Ramo,
  sourceFlow2Artifact: formData["Artefacto de flujo 2 (JSON)"],
  sourceExcel: formData["Excel de coberturas (pega el enlace)"],
  coverRecords,
  unmatchedDependencies: $("Translate Dependency Values").all().map(i => i.json).filter(m => m.decision !== "match")
});

return [{ json: reviewJson }];

const timestamp = new Date().toISOString().replace(/[:.]/g, "-");
return [{
  json: {
    ...$json,
    filename: `coverage_insert_draft_${$json.product_company_id}_${timestamp}.json`
  }
}];
